async function boot() {
  setupViewportUnits();
  setupEmailGate();
  if (state.requiresEmailGate) {
    state.loadingReady = true;
    showLoadingStart();
    return;
  }
  await initializeStudioApp();
  await finishAppLoading();
}

async function initializeStudioApp() {
  if (state.studioInitialized) return;
  if (state.studioInitializing) {
    await state.studioInitializing;
    return;
  }
  state.studioInitializing = initializeStudioAppOnce();
  try {
    await state.studioInitializing;
    state.studioInitialized = true;
  } finally {
    state.studioInitializing = null;
  }
}

async function initializeStudioAppOnce() {
  setupAdminMode();
  setupProductSwitcher();
  setupHypeChainControls();
  els.chooseFile.addEventListener('keydown', (event) => {
    if (event.key !== 'Enter' && event.key !== ' ') return;
    event.preventDefault();
    els.fileInput.click();
  });
  els.fileInput.addEventListener('change', () => handleFiles(els.fileInput.files));
  els.illuminateToggle.addEventListener('change', () => {
    state.illuminated = els.illuminateToggle.checked;
    applyIllumination();
  });
  els.removeBg.addEventListener('change', () => {
    state.removeBg = els.removeBg.checked;
    reprocess();
  });
  document.querySelectorAll('[data-size]').forEach((button) => {
    button.addEventListener('click', () => {
      document.querySelectorAll('[data-size]').forEach((b) => b.classList.remove('active'));
      button.classList.add('active');
      state.size = button.dataset.size;
      updateStats();
      schedulePreviewRender();
    });
  });
  document.querySelectorAll('[data-usage]').forEach((button) => {
    button.addEventListener('click', () => {
      document.querySelectorAll('[data-usage]').forEach((b) => b.classList.remove('active'));
      button.classList.add('active');
      state.usage = USAGE_PRESETS[button.dataset.usage] ? button.dataset.usage : 'indoor';
      updateStats();
      updateProjectControls();
    });
  });
  els.submitDesign?.addEventListener('click', () => submitDesignRequest());
  els.placeOrder.addEventListener('click', () => placeOrderRequest());
  els.saveProject.addEventListener('click', () => saveProjectFile());
  els.openProject.addEventListener('click', () => els.projectFileInput.click());
  els.projectFileInput.addEventListener('change', () => openProjectFiles(els.projectFileInput.files));
  els.designName.addEventListener('input', () => {
    state.designName = els.designName.value;
    renderPreviewTitle();
    updateProjectControls();
  });
  els.designName.addEventListener('keydown', (event) => {
    if (event.key === 'Enter') finishDesignNameEdit();
    if (event.key === 'Escape') finishDesignNameEdit();
  });
  els.designName.addEventListener('blur', finishDesignNameEdit);
  els.editDesignName.addEventListener('click', startDesignNameEdit);
  els.sideColourButton.addEventListener('click', () => openShellColourPopover('side', els.sideColourButton));
  els.backColourButton.addEventListener('click', () => openShellColourPopover('back', els.backColourButton));
  els.wizardClose.addEventListener('click', () => {
    if (state.uploadTarget === 'hype') restoreLedUploadState();
    closeWizard();
  });
  els.zoomOut.addEventListener('click', () => setWizardZoom(state.edit.zoom - 0.1));
  els.zoomIn.addEventListener('click', () => setWizardZoom(state.edit.zoom + 0.1));
  els.previewZoomOut.addEventListener('click', () => setPreviewZoom(state.previewZoom - 0.15));
  els.previewZoomIn.addEventListener('click', () => setPreviewZoom(state.previewZoom + 0.15));
  els.previewZoomReset.addEventListener('click', resetPreviewView);
  els.stage.addEventListener('wheel', (event) => {
    event.preventDefault();
    setPreviewZoom(state.previewZoom + (event.deltaY < 0 ? 0.12 : -0.12));
  }, { passive: false });
  els.stage.addEventListener('click', (event) => {
    if (event.target.closest('[data-open-preview-alert]')) {
      els.previewAlert.classList.add('expanded');
      return;
    }
    if (!event.target.closest('[data-close-preview-alert]')) return;
    els.previewAlert.classList.remove('expanded');
  });
  els.closeColourPopover.addEventListener('click', closeColourPopover);
  els.popoverHex.addEventListener('change', () => applySelectedColour(normalizeHex(els.popoverHex.value)));
  els.customColourInput.addEventListener('input', () => applySelectedColour(els.customColourInput.value));
  [els.rgbR, els.rgbG, els.rgbB].forEach((input) => input.addEventListener('input', () => applyRgbInputs()));
  document.querySelectorAll('[data-popover-tab]').forEach((button) => {
    button.addEventListener('click', () => setPopoverTab(button.dataset.popoverTab));
  });
  buildPresetGrid();
  setupDropZone();
  setupDragRotation();
  setupPreviewTouchGestures();
  setupProjectAccordion();
  setupCropInteraction();
  initThreeStage();
  updateStats();
  applyIllumination();
  renderShellColourControls();
  applyHypeStateToControls();
  refreshProjectLog();
  await loadDefaultPreview();
}

function setupEmailGate() {
  if (!els.emailGateForm || !els.customerEmail) return;
  const savedEmail = normalizeEmail(localStorage.getItem(EMAIL_STORAGE_KEY));
  if (savedEmail && isValidEmail(savedEmail)) {
    state.customerEmail = savedEmail;
    els.customerEmail.value = savedEmail;
    state.requiresEmailGate = false;
    els.emailGateForm.classList.add('hidden');
    renderSessionEmail();
    queueEmailMarketingSubscription(savedEmail);
    refreshProjectLog();
    return;
  }
  state.requiresEmailGate = true;
  els.emailGateForm.classList.remove('hidden');
  els.customerEmail.disabled = false;
  els.customerEmail.readOnly = false;
  els.appLoadingCard?.classList.add('needs-email');
  if (els.loadingStartButton) {
    els.loadingStartButton.disabled = true;
    els.loadingStartButton.textContent = 'Loading...';
  }
  focusEmailGateInput();
  els.emailGateForm.addEventListener('submit', async (event) => {
    event.preventDefault();
    const email = els.customerEmail.value.trim();
    if (!isValidEmail(email)) {
      els.emailGateForm.classList.add('invalid');
      els.emailGateError.textContent = 'Enter a valid email address to continue.';
      els.customerEmail.focus();
      return;
    }
    state.customerEmail = normalizeEmail(email);
    localStorage.setItem(EMAIL_STORAGE_KEY, state.customerEmail);
    queueEmailMarketingSubscription(state.customerEmail);
    renderSessionEmail();
    if (!state.studioInitialized) {
      if (els.loadingStartButton) {
        els.loadingStartButton.disabled = true;
        els.loadingStartButton.textContent = 'Loading...';
      }
      els.emailGateError.textContent = '';
      await initializeStudioApp();
    }
    els.emailGateForm.classList.add('hidden');
    els.emailGateError.textContent = '';
    setStatus('Ready');
    refreshProjectLog();
    hideAppLoading();
  });
  els.customerEmail.addEventListener('input', () => {
    els.emailGateForm.classList.remove('invalid');
    els.emailGateError.textContent = '';
  });
}

function isValidEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function normalizeEmail(value) {
  return String(value || '').trim().toLowerCase();
}

function queueEmailMarketingSubscription(value, source = EMAIL_MARKETING_SOURCE) {
  const email = normalizeEmail(value);
  if (!isValidEmail(email) || emailMarketingSubmitted.has(email)) return;
  emailMarketingSubmitted.add(email);
  writeEmailMarketingSessionSet();
  const endpoint = getEmailMarketingSubscribeEndpoint();
  if (!endpoint) return;
  fetch(endpoint, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ email, source }),
  }).then((response) => {
    if (!response.ok) throw new Error(`Shopify subscribe returned ${response.status}`);
  }).catch((error) => {
    console.warn('Could not add email to Shopify marketing subscribers.', error);
  });
}

function getEmailMarketingSubscribeEndpoint() {
  if (window.SIGN_GUY_SHOPIFY_SUBSCRIBE_ENDPOINT) return window.SIGN_GUY_SHOPIFY_SUBSCRIBE_ENDPOINT;
  if (!window.location.protocol.startsWith('http')) return '';
  return new URL('/api/shopify/subscribe', window.location.href).href;
}

function readEmailMarketingSessionSet() {
  try {
    return JSON.parse(sessionStorage.getItem(EMAIL_MARKETING_SESSION_KEY) || '[]')
      .map((email) => normalizeEmail(email))
      .filter((email) => isValidEmail(email));
  } catch {
    return [];
  }
}

function writeEmailMarketingSessionSet() {
  try {
    sessionStorage.setItem(EMAIL_MARKETING_SESSION_KEY, JSON.stringify([...emailMarketingSubmitted]));
  } catch {
    // Session storage is a convenience only; in-memory de-dupe still applies.
  }
}

function renderSessionEmail() {
  if (!els.sessionEmailStat) return;
  els.sessionEmailStat.textContent = state.customerEmail || 'No email';
}

function setupAdminMode() {
  state.isAdmin = sessionStorage.getItem(ADMIN_SESSION_KEY) === 'true';
  renderAdminMode();
  els.adminLoginButton?.addEventListener('click', () => {
    if (state.isAdmin) {
      logoutAdmin();
      return;
    }
    openAdminGate();
  });
  els.adminCancel?.addEventListener('click', closeAdminGate);
  els.adminGateForm?.addEventListener('submit', async (event) => {
    event.preventDefault();
    await loginAdmin();
  });
  els.adminPassword?.addEventListener('input', () => {
    els.adminGate?.classList.remove('invalid');
    if (els.adminGateError) els.adminGateError.textContent = '';
  });
}

function setupViewportUnits() {
  updateViewportUnits();
  window.addEventListener('resize', updateViewportUnits);
  window.visualViewport?.addEventListener('resize', updateViewportUnits);
  window.visualViewport?.addEventListener('scroll', updateViewportUnits);
}

function updateViewportUnits() {
  const height = window.visualViewport?.height || window.innerHeight;
  document.documentElement.style.setProperty('--app-vh', `${height}px`);
}

function renderAdminMode() {
  if (els.adminLoginButton) {
    els.adminLoginButton.textContent = state.isAdmin ? 'Admin: Logout' : 'Login';
    els.adminLoginButton.classList.toggle('active', state.isAdmin);
  }
  renderProductAccess();
  renderHypeVariantAccess();
  renderDiagnostics();
  renderProjectLog();
  updateStats();
}

function setupProductSwitcher() {
  els.productTabs.forEach((button) => {
    button.addEventListener('click', () => {
      const productType = button.dataset.productType || 'led';
      if (!canAccessProduct(productType)) return;
      selectProductType(productType);
    });
  });
  renderProductAccess();
  selectProductType(state.productType);
}

function canAccessProduct(productType) {
  return productType === 'led' || productType === 'hype' || state.isAdmin;
}

function renderProductAccess() {
  els.productTabs.forEach((button) => {
    const productType = button.dataset.productType || 'led';
    const locked = !canAccessProduct(productType);
    button.setAttribute('aria-disabled', locked ? 'true' : 'false');
    button.classList.toggle('product-tab-locked', locked);
    const lock = button.querySelector('.product-lock');
    if (lock) lock.hidden = !locked;
    if (locked) {
      button.setAttribute('aria-describedby', 'productLockTooltip');
    } else {
      button.removeAttribute('aria-describedby');
    }
  });
  if (!canAccessProduct(state.productType)) selectProductType('led');
}

function selectProductType(productType) {
  const next = canAccessProduct(productType) ? productType : 'led';
  state.productType = next;
  document.body.classList.toggle('product-led', next === 'led');
  document.body.classList.toggle('product-hype', next === 'hype');
  document.body.classList.toggle('product-plaque', next === 'plaque');
  els.productTabs.forEach((button) => {
    const active = button.dataset.productType === next;
    button.classList.toggle('active', active);
    button.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
  els.ledStudioSections.forEach((section) => section.classList.toggle('hidden', next !== 'led'));
  els.hypeChainControls?.classList.toggle('hidden', next !== 'hype');
  els.plaqueStudio?.classList.toggle('hidden', next !== 'plaque');
  els.hypePreview?.classList.toggle('hidden', next !== 'hype');
  if (next === 'hype') {
    initializeHypeChainPreview();
    if (!state.hype.logoDataUrl && !state.hypeDefaultProjectLoading) {
      loadDefaultHypeChainProject();
    }
    renderHypeChain();
  } else if (next === 'led') {
    renderPreviewTitle();
    renderThree();
  } else {
    els.previewTitle.textContent = '3D Wall Plaque';
  }
  updateProductCta();
  updateStats();
  updateProjectControls();
  refreshProjectLog();
}

function updateProductCta() {
  if (!els.placeOrder) return;
  els.placeOrder.textContent = state.productType === 'hype' ? 'Place Order' : 'Place Order';
}

function setupHypeChainControls() {
  document.querySelectorAll('[data-hype-variant]').forEach((button) => {
    button.addEventListener('click', () => {
      if (button.dataset.hypeVariant === 'spinner' && !state.isAdmin) return;
      document.querySelectorAll('[data-hype-variant]').forEach((item) => item.classList.remove('active'));
      button.classList.add('active');
      state.hype.variant = button.dataset.hypeVariant || 'classic';
      updateStats();
      scheduleHypeRender();
    });
  });
  els.hypeColourButtons.forEach((button) => {
    button.addEventListener('click', () => openHypeColourPopover(button.dataset.hypeColour, button));
  });
  [
    [els.hypePrimaryColour, 'primary'],
    [els.hypeSecondaryColour, 'secondary'],
    [els.hypeTertiaryColour, 'tertiary'],
    [els.hypePendantColour, 'pendant'],
    [els.hypePendantText, 'text'],
    [els.hypePatternLength, 'patternLength'],
    [els.hypeChainLength, 'chainLength'],
    [els.hypeQuantity, 'quantity'],
  ].forEach(([input, key]) => {
    input?.addEventListener('input', () => {
      state.hype[key] = input.type === 'number' || input.type === 'range'
        ? Number(input.value)
        : input.value;
      if (key === 'patternLength') {
        state.hype.patternLength = getHypePatternLength(input.value);
        renderHypeColourControls();
      }
      if (key === 'chainLength') {
        state.hype.chainLength = normalizeHypeChainLength(state.hype.chainLength);
        state.hype.linkCount = getDefaultHypeLinkCount(state.hype.chainLength);
      }
      if (key === 'chainLength' || key === 'patternLength') updateStats();
      syncHypeDerivedColours();
      scheduleHypeRender(0);
    });
  });
  els.hypeLogoInput?.addEventListener('change', async () => {
    const file = els.hypeLogoInput.files?.[0];
    if (!file) return;
    await handleFiles(els.hypeLogoInput.files, { target: 'hype' });
    els.hypeLogoInput.value = '';
  });
  setupFileButtonKeyboard(els.hypeChooseFile, els.hypeLogoInput);
  setupDropZone(els.hypeDropZone, (files) => handleFiles(files, { target: 'hype' }));
  setupHypeDrag();
}

function initializeHypeChainPreview() {
  if (state.hype.initialized) return;
  state.hype.initialized = true;
  initHypeThreeStage();
  els.hypePreview?.classList.add('loading');
  window.setTimeout(() => {
    els.hypePreview?.classList.remove('loading');
    renderHypeChain();
  }, 260);
}

function scheduleHypeRender(delay = 120) {
  if (state.hype.renderTimer) clearTimeout(state.hype.renderTimer);
  els.hypePreview?.classList.add('loading');
  state.hype.renderTimer = window.setTimeout(() => {
    state.hype.renderTimer = null;
    renderHypeChain();
    els.hypePreview?.classList.remove('loading');
  }, delay);
}

function renderHypeChain() {
  if (!els.hypeChainRender) return;
  syncHypeDerivedColours();
  renderHypeColourControls();
  renderHypeVariantAccess();
  const hype = state.hype;
  els.hypeVariantOutput.textContent = getHypeSpecLabel();
  els.hypeChainRender.style.setProperty('--hype-primary', normalizeHex(hype.primary));
  els.hypeChainRender.style.setProperty('--hype-secondary', normalizeHex(hype.secondary));
  els.hypeChainRender.style.setProperty('--hype-tertiary', normalizeHex(hype.tertiary));
  els.hypeChainRender.style.setProperty('--hype-accent', normalizeHex(hype.accent || '#ffc529'));
  els.hypeChainRender.style.setProperty('--hype-pendant', getHypePendantBodyColour());
  els.hypeChainRender.style.setProperty('--hype-border', normalizeHex(hype.border));
  updateHypeCssRotation();
  els.hypeChainRender.style.setProperty('--hype-zoom', state.productType === 'hype' ? state.previewZoom.toFixed(3) : '1');
  const previewPan = getPreviewPan();
  els.hypeChainRender.style.setProperty('--preview-pan-x', `${previewPan.x.toFixed(1)}px`);
  els.hypeChainRender.style.setProperty('--preview-pan-y', `${previewPan.y.toFixed(1)}px`);
  renderHypeLinks();
  buildHypeThreeModel();
  els.hypePendantPreview.style.borderWidth = hype.logoDataUrl ? '0px' : '10px';
  els.hypePendantPreview.style.borderRadius = hype.logoDataUrl ? '0' : '30px';
  els.hypePendantPreview.classList.toggle('has-logo', Boolean(hype.logoDataUrl));
  const hasUserUploadedHypeLogo = Boolean(hype.logoDataUrl && !hype.isExampleProject);
  if (els.hypeChooseFileText) els.hypeChooseFileText.textContent = hasUserUploadedHypeLogo ? 'Choose a different logo' : 'Upload logo';
  els.hypePendantTextPreview.textContent = '';
  els.hypePendantTextPreview.hidden = true;
  if (hype.logoDataUrl) {
    els.hypeLogoPreview.src = hype.logoDataUrl;
    els.hypeLogoPreview.hidden = false;
  } else {
    els.hypeLogoPreview.hidden = true;
  }
  renderPreviewTitle();
}

function initHypeThreeStage() {
  if (state.hypeThree || !window.THREE || !els.hypePreview) return;
  const renderer = new THREE.WebGLRenderer({
    antialias: true,
    alpha: true,
    preserveDrawingBuffer: true,
    logarithmicDepthBuffer: true,
  });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
  renderer.shadowMap.enabled = true;
  renderer.shadowMap.type = THREE.PCFSoftShadowMap;
  renderer.sortObjects = true;
  renderer.outputEncoding = THREE.sRGBEncoding;
  if (THREE.ACESFilmicToneMapping) renderer.toneMapping = THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.02;
  renderer.domElement.className = 'hype-three-canvas';
  els.hypePreview.appendChild(renderer.domElement);

  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(36, 1, HYPE_CAMERA_NEAR, HYPE_CAMERA_FAR);
  camera.position.set(0, 18, HYPE_CAMERA_DISTANCE);
  camera.lookAt(0, HYPE_CAMERA_TARGET_Y, 0);

  const hemi = new THREE.HemisphereLight(0xffffff, 0x151515, 0.9);
  scene.add(hemi);
  const key = new THREE.DirectionalLight(0xfff1d2, 0.9);
  key.position.set(-120, 190, 260);
  key.castShadow = true;
  key.shadow.mapSize.set(1024, 1024);
  scene.add(key);
  const rim = new THREE.DirectionalLight(0x9fb5ff, 0.45);
  rim.position.set(180, 70, -210);
  scene.add(rim);
  const floor = new THREE.Mesh(
    new THREE.PlaneBufferGeometry(560, 360),
    new THREE.ShadowMaterial({ color: 0x000000, opacity: 0.28 }),
  );
  floor.rotation.x = -Math.PI / 2;
  floor.position.y = -126;
  floor.position.z = -12;
  floor.receiveShadow = true;
  scene.add(floor);

  state.hypeThree = {
    renderer,
    scene,
    camera,
    group: null,
    pendantGroup: null,
    focusLocal: null,
    focusTarget: new THREE.Vector3(0, HYPE_CAMERA_TARGET_Y, 0),
    cameraTween: null,
    resources: [],
    resizeObserver: null,
    stlGeometries: null,
    stlLoadPromise: null,
  };
  els.hypePreview.classList.add('hype-three-active');
  resizeHypeThree();
  if (window.ResizeObserver) {
    state.hypeThree.resizeObserver = new ResizeObserver(() => resizeHypeThree());
    state.hypeThree.resizeObserver.observe(els.hypePreview);
  }
  window.addEventListener('resize', resizeHypeThree);
}

function resizeHypeThree() {
  if (!state.hypeThree || !els.hypePreview) return;
  const rect = els.hypePreview.getBoundingClientRect();
  state.hypeThree.renderer.setSize(Math.max(1, rect.width), Math.max(1, rect.height), false);
  state.hypeThree.camera.aspect = Math.max(1, rect.width) / Math.max(1, rect.height);
  state.hypeThree.camera.near = HYPE_CAMERA_NEAR;
  state.hypeThree.camera.far = HYPE_CAMERA_FAR;
  frameHypeCamera();
  state.hypeThree.camera.updateProjectionMatrix();
  renderHypeThree();
}

function clearHypeThreeModel() {
  if (!state.hypeThree) return;
  if (state.hypeThree.cameraTween) window.cancelAnimationFrame(state.hypeThree.cameraTween);
  state.hypeThree.cameraTween = null;
  if (state.hypeThree.group) state.hypeThree.scene.remove(state.hypeThree.group);
  state.hypeThree.resources.forEach((resource) => resource?.dispose?.());
  state.hypeThree.group = null;
  state.hypeThree.pendantGroup = null;
  state.hypeThree.resources = [];
}

function renderHypeThree() {
  if (!state.hypeThree) return;
  state.hypeThree.renderer.render(state.hypeThree.scene, state.hypeThree.camera);
}

function updateHypeThreeRotation() {
  if (!state.hypeThree?.group || !window.THREE) return;
  applyHypeGroupRotation();
  frameHypeCamera();
  renderHypeThree();
}

function applyHypeGroupRotation() {
  if (!state.hypeThree?.group || !window.THREE) return;
  const group = state.hypeThree.group;
  state.hypeThree.group.rotation.order = 'YXZ';
  group.rotation.x = THREE.Math.degToRad(state.hype.rotation.x);
  group.rotation.y = THREE.Math.degToRad(state.hype.rotation.y);
  const focusLocal = state.hypeThree.focusLocal;
  if (!focusLocal) {
    const pan = getPreviewPan();
    group.position.set(pan.x * 0.42, -pan.y * 0.42, 0);
    group.updateMatrixWorld(true);
    return;
  }
  const rotatedFocus = focusLocal.clone().applyEuler(group.rotation);
  group.position.copy(focusLocal).sub(rotatedFocus);
  const pan = getPreviewPan();
  group.position.x += pan.x * 0.42;
  group.position.y -= pan.y * 0.42;
  group.updateMatrixWorld(true);
}

function frameHypeCamera(options = {}) {
  if (!state.hypeThree?.camera || !window.THREE) return;
  const camera = state.hypeThree.camera;
  const target = state.hypeThree.focusTarget || new THREE.Vector3(0, HYPE_CAMERA_TARGET_Y, 0);
  const limits = getPreviewZoomLimits();
  const zoom = clamp(Number(state.previewZoom) || 1, limits.min, limits.max);
  const distance = HYPE_CAMERA_DISTANCE / zoom;
  const viewTarget = new THREE.Vector3(target.x, target.y + HYPE_CAMERA_VIEW_OFFSET_Y, target.z);
  const nextPosition = new THREE.Vector3(viewTarget.x, viewTarget.y + 36, viewTarget.z + distance);
  if (!options.smooth || typeof window.requestAnimationFrame !== 'function') {
    if (state.hypeThree.cameraTween) window.cancelAnimationFrame(state.hypeThree.cameraTween);
    state.hypeThree.cameraTween = null;
    camera.position.copy(nextPosition);
    camera.lookAt(viewTarget.x, viewTarget.y, viewTarget.z);
    state.hypeThree._cameraLookTarget = viewTarget.clone();
    return;
  }
  if (state.hypeThree.cameraTween) window.cancelAnimationFrame(state.hypeThree.cameraTween);
  const startPosition = camera.position.clone();
  const startTarget = state.hypeThree._cameraLookTarget?.clone?.() || viewTarget.clone();
  const endTarget = viewTarget.clone();
  const startedAt = performance.now();
  const duration = 180;
  const tick = (now) => {
    const t = clamp((now - startedAt) / duration, 0, 1);
    const eased = 1 - Math.pow(1 - t, 3);
    camera.position.lerpVectors(startPosition, nextPosition, eased);
    const currentTarget = startTarget.clone().lerp(endTarget, eased);
    camera.lookAt(currentTarget.x, currentTarget.y, currentTarget.z);
    state.hypeThree._cameraLookTarget = currentTarget;
    renderHypeThree();
    if (t < 1) {
      state.hypeThree.cameraTween = window.requestAnimationFrame(tick);
    } else {
      state.hypeThree.cameraTween = null;
    }
  };
  state.hypeThree.cameraTween = window.requestAnimationFrame(tick);
}

function updateHypeCameraFocus(preferredObject = null) {
  if (!state.hypeThree?.group || !window.THREE) return;
  const focusObject = preferredObject || (state.hype.logoDataUrl ? state.hypeThree.pendantGroup : state.hypeThree.group);
  const box = new THREE.Box3().setFromObject(focusObject || state.hypeThree.group);
  if (!Number.isFinite(box.min.x) || box.isEmpty()) {
    state.hypeThree.focusLocal = new THREE.Vector3(0, HYPE_CAMERA_TARGET_Y, 0);
    state.hypeThree.focusTarget.copy(state.hypeThree.focusLocal);
  } else {
    const center = box.getCenter(new THREE.Vector3());
    const localCenter = state.hypeThree.group.worldToLocal(center.clone());
    state.hypeThree.focusLocal = localCenter;
    state.hypeThree.focusTarget.copy(center);
  }
  applyHypeGroupRotation();
  const worldTarget = state.hypeThree.group.localToWorld(state.hypeThree.focusLocal.clone());
  state.hypeThree.focusTarget.copy(worldTarget);
  frameHypeCamera();
}

function updateHypeCssRotation() {
  if (!els.hypeChainRender) return;
  els.hypeChainRender.style.setProperty('--hype-tilt-x', `${state.hype.rotation.x}deg`);
  els.hypeChainRender.style.setProperty('--hype-tilt-y', `${state.hype.rotation.y}deg`);
}

async function loadHypeStlGeometries() {
  if (!state.hypeThree || !window.THREE) return null;
  if (state.hypeThree.stlGeometries) return state.hypeThree.stlGeometries;
  if (state.hypeThree.stlLoadPromise) return state.hypeThree.stlLoadPromise;
  els.hypePreview?.classList.add('loading');
  state.hypeThree.stlLoadPromise = Promise.all([
    fetchStlGeometry(HYPE_CHAIN_STL_ASSETS.link, 'link'),
    fetchStlGeometry(HYPE_CHAIN_STL_ASSETS.connector, 'connector'),
    fetchOptionalStlGeometry(HYPE_CHAIN_STL_ASSETS.hook, 'hook'),
  ]).then(([link, connector, hook]) => {
    state.hypeThree.stlGeometries = { link, connector, hook };
    state.hypeThree.stlLoadPromise = null;
    els.hypePreview?.classList.remove('loading');
    return state.hypeThree.stlGeometries;
  }).catch((error) => {
    state.hypeThree.stlLoadPromise = null;
    throw error;
  });
  return state.hypeThree.stlLoadPromise;
}

async function fetchOptionalStlGeometry(url, embeddedKey) {
  try {
    return await fetchStlGeometry(url, embeddedKey);
  } catch (error) {
    console.error(`Optional STL unavailable: ${url}`, error);
    return null;
  }
}

async function fetchStlGeometry(url, embeddedKey) {
  let buffer = null;
  try {
    const response = await fetch(url);
    if (response.ok) buffer = await response.arrayBuffer();
  } catch (error) {
    buffer = null;
  }
  if (!buffer && HYPE_CHAIN_STL_EMBEDDED[embeddedKey]) {
    buffer = base64ToArrayBuffer(HYPE_CHAIN_STL_EMBEDDED[embeddedKey]);
  }
  if (!buffer) throw new Error(`Failed to load STL: ${url}`);
  const geometry = parseBinaryStlGeometry(buffer);
  normalizeStlGeometry(geometry);
  geometry.computeBoundingSphere();
  geometry.computeVertexNormals();
  console.info(`Loaded Hype Chain STL: ${embeddedKey}`, {
    url,
    triangles: Math.round((geometry.getAttribute('position')?.count || 0) / 3),
  });
  return geometry;
}

function base64ToArrayBuffer(base64) {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}

function parseBinaryStlGeometry(buffer) {
  const view = new DataView(buffer);
  const triangleCount = view.getUint32(80, true);
  const expectedLength = 84 + triangleCount * 50;
  if (buffer.byteLength < expectedLength) throw new Error('Invalid binary STL file');
  const positions = new Float32Array(triangleCount * 9);
  const normals = new Float32Array(triangleCount * 9);
  let positionOffset = 0;
  for (let triangle = 0; triangle < triangleCount; triangle += 1) {
    const base = 84 + triangle * 50;
    const normal = [
      view.getFloat32(base, true),
      view.getFloat32(base + 4, true),
      view.getFloat32(base + 8, true),
    ];
    for (let vertex = 0; vertex < 3; vertex += 1) {
      const vertexOffset = base + 12 + vertex * 12;
      positions[positionOffset] = view.getFloat32(vertexOffset, true);
      normals[positionOffset] = normal[0];
      positionOffset += 1;
      positions[positionOffset] = view.getFloat32(vertexOffset + 4, true);
      normals[positionOffset] = normal[1];
      positionOffset += 1;
      positions[positionOffset] = view.getFloat32(vertexOffset + 8, true);
      normals[positionOffset] = normal[2];
      positionOffset += 1;
    }
  }
  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  geometry.setAttribute('normal', new THREE.BufferAttribute(normals, 3));
  return geometry;
}

function normalizeStlGeometry(geometry) {
  geometry.computeBoundingBox();
  const box = geometry.boundingBox;
  const center = new THREE.Vector3();
  box.getCenter(center);
  geometry.translate(-center.x, -center.y, -center.z);
}

function buildHypeThreeModel() {
  if (!state.hypeThree || !window.THREE) return;
  if (!state.hypeThree.stlGeometries) {
    loadHypeStlGeometries().then(() => scheduleHypeRender(0)).catch(() => {
      els.hypePreview?.classList.remove('loading');
      setStatus('Could not load Hype Chain STL files');
    });
    return;
  }
  clearHypeThreeModel();
  const resources = state.hypeThree.resources;
  const group = new THREE.Group();
  group.name = 'articulatedHypeChain';
  group.rotation.order = 'YXZ';
  group.rotation.x = THREE.Math.degToRad(state.hype.rotation.x);
  group.rotation.y = THREE.Math.degToRad(state.hype.rotation.y);

  const primaryMaterial = makeHypeSilkMaterial(state.hype.primary || '#111111');
  const secondaryMaterial = makeHypeSilkMaterial(state.hype.secondary || '#ffc529');
  const connectorMaterial = makeHypeSilkMaterial(state.hype.primary || '#111111');
  const attachmentMaterial = makeHypeSilkMaterial(state.hype.primary || '#111111');
  const pendantMaterial = makeHypeSilkMaterial(getHypePendantBodyColour());
  resources.push(primaryMaterial, secondaryMaterial, connectorMaterial, attachmentMaterial, pendantMaterial);

  const linkGeometry = state.hypeThree.stlGeometries.link;
  const connectorGeometry = state.hypeThree.stlGeometries.connector;
  const uploadedChainDropY = state.hype.logoDataUrl ? HYPE_UPLOADED_CHAIN_DROP_Y : 0;
  const chainRig = new THREE.Group();
  chainRig.name = 'hypeChainAttachmentRig';
  chainRig.position.y = uploadedChainDropY;

  const linkCount = getHypeLinkCount(state.hype.chainLength, state.hype.linkCount);
  const patternMaterials = getHypePatternColours().map((hex) => makeHypeSilkMaterial(hex));
  resources.push(...patternMaterials);
  const chainLinks = buildHypeChainLoop({
    linkCount,
    linkGeometry,
    materials: patternMaterials,
  });
  chainRig.add(chainLinks.root);
  const connectorEntryLinks = makeHypeConnectorEntryLinks(linkGeometry, patternMaterials, chainLinks.count);
  chainRig.add(connectorEntryLinks);

  const connector = new THREE.Mesh(connectorGeometry, connectorMaterial);
  connector.name = 'stlFusedThreeWayChainConnector';
  connector.position.set(0, -106, 0);
  connector.castShadow = true;
  connector.receiveShadow = true;
  chainRig.add(connector);

  const attachmentLink = new THREE.Mesh(linkGeometry, attachmentMaterial);
  attachmentLink.name = 'pendantAttachmentLink';
  attachmentLink.position.set(0, state.hype.logoDataUrl ? -140 : -137, state.hype.logoDataUrl ? -2 : 4);
  attachmentLink.rotation.z = Math.PI / 2;
  attachmentLink.rotation.y = THREE.Math.degToRad(68);
  attachmentLink.castShadow = true;
  attachmentLink.receiveShadow = true;
  chainRig.add(attachmentLink);
  group.add(chainRig);

  const pendant = makeHypePendantMesh(pendantMaterial, resources);
  pendant.position.set(0, state.hype.logoDataUrl ? -286 : -202, 0);
  group.add(pendant);

  state.hypeThree.group = group;
  state.hypeThree.pendantGroup = pendant;
  disableHypeFrustumCulling(group);
  state.hypeThree.scene.add(group);
  updateHypeCameraFocus(state.hype.logoDataUrl ? pendant : group);
  renderHypeThree();
}

function buildHypeChainLoop({ linkCount, linkGeometry, materials }) {
  const root = new THREE.Group();
  root.name = 'continuousArticulatedLinkLoop';
  const path = makeHypeChainPath();
  let leftEnd = root;
  let rightEnd = root;
  const linksOnPath = Math.max(16, linkCount + 4);
  path.arcLengthDivisions = Math.max(480, linksOnPath * 24);
  path.updateArcLengths();
  for (let i = 0; i < linksOnPath; i += 1) {
    const u = linksOnPath === 1 ? 0.5 : i / (linksOnPath - 1);
    const position = path.getPointAt(u);
    const pivot = new THREE.Group();
    pivot.name = `linkPivot${i}`;
    pivot.position.set(position.x, position.y, position.z);
    pivot.rotation.z = getHypeChainPathRotation(path, u);
    const mesh = createChainLink(linkGeometry, materials[i % materials.length], i);
    pivot.add(mesh);
    root.add(pivot);
    if (i === 0) leftEnd = pivot;
    if (i === linksOnPath - 1) rightEnd = pivot;
  }
  return { root, leftEnd, rightEnd, count: linksOnPath };
}

function makeHypeConnectorEntryLinks(linkGeometry, materials, startIndex = 0) {
  const group = new THREE.Group();
  group.name = 'connectorThreadedEntryLinks';
  const secondaryMaterial = materials[1] || materials[0];
  const path = makeHypeChainPath();
  const linksOnPath = Math.max(16, startIndex || 0);
  path.arcLengthDivisions = Math.max(480, linksOnPath * 24);
  path.updateArcLengths();
  const referenceStep = 1 / (linksOnPath - 1);
  const connectorOpenings = {
    left: new THREE.Vector3(-22, -106, 0),
    right: new THREE.Vector3(22, -106, 0),
  };
  const leftChainEnd = path.getPointAt(0);
  const rightChainEnd = path.getPointAt(1);
  const entries = [
    {
      name: 'lowerLeftConnectorEntryLink',
      position: leftChainEnd.clone().lerp(connectorOpenings.left, 0.68),
      u: referenceStep,
    },
    {
      name: 'lowerRightConnectorEntryLink',
      position: rightChainEnd.clone().lerp(connectorOpenings.right, 0.68),
      u: 1 - referenceStep,
    },
  ];
  entries.forEach((entry, offset) => {
    const pivot = new THREE.Group();
    pivot.name = `${entry.name}Pivot`;
    pivot.position.copy(entry.position);
    pivot.rotation.z = getHypeChainPathRotation(path, entry.u);
    const mesh = createChainLink(linkGeometry, secondaryMaterial, 1);
    mesh.name = entry.name;
    pivot.add(mesh);
    group.add(pivot);
  });
  return group;
}

function disableHypeFrustumCulling(object) {
  object.traverse?.((child) => {
    if (child.isMesh) child.frustumCulled = false;
  });
}

function getHypeChainPathRotation(path, u) {
  const tangent = path.getTangentAt(u);
  const tangentAngle = Math.atan2(tangent.y, tangent.x);
  return tangentAngle + Math.sin(u * Math.PI * 4) * THREE.Math.degToRad(1);
}

function createChainLink(linkGeometry, material, index) {
  const mesh = new THREE.Mesh(linkGeometry, material);
  mesh.name = `solidInterlockingLink${index}`;
  mesh.rotation.x = index % 2 === 0 ? 0 : Math.PI / 2;
  mesh.rotation.y = index % 2 === 0 ? THREE.Math.degToRad(2) : THREE.Math.degToRad(-2);
  mesh.position.x = index % 2 === 0 ? -2.4 : 2.4;
  mesh.position.z = index % 2 === 0 ? -2.8 : 2.8;
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  mesh.frustumCulled = false;
  return mesh;
}

function createChainLinkGeometry(width = 40, height = 24, radius = 8, tubeRadius = 4.2) {
  return makeRoundedRectangleTubeGeometry(width, height, radius, tubeRadius);
}

function createChainConnectorGeometry() {
  const horizontalLoop = createChainLinkGeometry(76, 26, 9, 4.6);
  const verticalLoop = createChainLinkGeometry(28, 58, 8, 4.6);
  verticalLoop.applyMatrix4(new THREE.Matrix4().makeTranslation(0, -4, 2));
  horizontalLoop.applyMatrix4(new THREE.Matrix4().makeTranslation(0, 0, 0));
  const geometry = mergeBufferGeometriesAsOne([horizontalLoop, verticalLoop]);
  horizontalLoop.dispose();
  verticalLoop.dispose();
  geometry.computeBoundingSphere();
  geometry.computeVertexNormals();
  return geometry;
}

function makeHypeChainPath() {
  return new THREE.CatmullRomCurve3([
    new THREE.Vector3(-66, -76, 4),
    new THREE.Vector3(-111, -51, 2),
    new THREE.Vector3(-143, -6, -2),
    new THREE.Vector3(-150, 92, -6),
    new THREE.Vector3(-96, 206, -9),
    new THREE.Vector3(0, 244, -10),
    new THREE.Vector3(96, 206, -9),
    new THREE.Vector3(150, 92, -6),
    new THREE.Vector3(143, -6, -2),
    new THREE.Vector3(111, -51, 2),
    new THREE.Vector3(66, -76, 4),
  ], false, 'catmullrom', 0.5);
}

function makeHypePendantMesh(material, resources) {
  if (state.hype.logoDataUrl) return makeHypeLogoPendantMesh(material, resources);
  const group = new THREE.Group();
  group.name = 'freeHangingPendant';
  const shape = new THREE.Shape();
  const w = 118;
  const h = 92;
  roundedRectShape(shape, -w / 2, -h / 2, w, h, 14);
  const hole = new THREE.Path();
  hole.absarc(0, h / 2 - 15, 10, 0, Math.PI * 2, true);
  shape.holes.push(hole);
  const geometry = new THREE.ExtrudeBufferGeometry(shape, {
    depth: 14,
    bevelEnabled: true,
    bevelThickness: 2.5,
    bevelSize: 2.5,
    bevelSegments: 5,
    curveSegments: 18,
  });
  geometry.center();
  resources.push(geometry);
  const mesh = new THREE.Mesh(geometry, material);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  group.add(mesh);
  const reinforcementGeometry = makeRoundedRectangleTubeGeometry(34, 24, 9, 4.2);
  resources.push(reinforcementGeometry);
  const reinforcement = new THREE.Mesh(reinforcementGeometry, material);
  reinforcement.position.set(0, h / 2 - 15, 9);
  reinforcement.castShadow = true;
  reinforcement.receiveShadow = true;
  group.add(reinforcement);
  return group;
}

function makeHypeLogoPendantMesh(material, resources) {
  const group = new THREE.Group();
  group.name = 'uploadedLogoPendant';
  group.scale.set(2.25, 2.25, 2.25);
  const pendantSize = getHypeLogoPendantSize();
  const pendantDepth = 11;
  const texture = new THREE.TextureLoader().load(state.hype.logoDataUrl, () => {
    texture.needsUpdate = true;
    renderHypeThree();
  });
  texture.encoding = THREE.sRGBEncoding;
  texture.anisotropy = Math.min(state.hypeThree?.renderer?.capabilities?.getMaxAnisotropy?.() || 4, 8);
  texture.minFilter = THREE.LinearFilter;
  texture.magFilter = THREE.LinearFilter;
  texture.generateMipmaps = false;
  resources.push(texture);

  const logoMaterial = new THREE.MeshStandardMaterial({
    map: texture,
    color: 0xffffff,
    roughness: 0.28,
    metalness: 0.16,
    transparent: true,
    alphaTest: 0.04,
    side: THREE.FrontSide,
    depthWrite: false,
    polygonOffset: true,
    polygonOffsetFactor: -12,
    polygonOffsetUnits: -12,
  });
  const bodyMaterial = makeHypeSilkMaterial(getHypePendantBodyColour());
  bodyMaterial.polygonOffset = true;
  bodyMaterial.polygonOffsetFactor = 2;
  bodyMaterial.polygonOffsetUnits = 2;
  resources.push(logoMaterial, bodyMaterial);

  createHypeLogoPendantFromAlpha(state.hype.logoDataUrl, {
    bodyMaterial,
    logoMaterial,
    resources,
    group,
    pendantSize,
    depth: pendantDepth,
  });
  return group;
}

function getHypeLogoPendantSize() {
  const aspect = clamp(Number(state.hype.logoAspect) || 1, 0.35, 2.4);
  const maxWidth = 142;
  const maxHeight = 112;
  let width = maxWidth;
  let height = width / aspect;
  if (height > maxHeight) {
    height = maxHeight;
    width = height * aspect;
  }
  return { width, height };
}

function getHypePendantBodyColour() {
  return normalizeHex(state.hype.pendantCasing || state.hype.pendant || '#202326');
}

function createHypeLogoPendantFromAlpha(dataUrl, options) {
  const {
    bodyMaterial,
    logoMaterial,
    resources,
    group,
    pendantSize,
    depth,
  } = options;
  const image = new Image();
  image.onload = () => {
    if (!state.hypeThree?.group || group.parent !== state.hypeThree.group) return;
    const silhouette = makeAlphaSilhouettePendantShape(image, pendantSize.width, pendantSize.height);
    const pendantOffsetX = -(Number(silhouette.hookAnchorX) || 0);
    const bodyGeometry = makeAlphaSilhouettePendantGeometry(silhouette.shape, depth);
    resources.push(bodyGeometry);
    const body = new THREE.Mesh(bodyGeometry, bodyMaterial);
    body.name = 'uploadedLogoPendantSolidBody';
    body.position.set(pendantOffsetX, -10, 0);
    body.renderOrder = 1;
    body.castShadow = true;
    body.receiveShadow = true;
    body.frustumCulled = false;
    group.add(body);

    const faceGeometry = new THREE.ShapeBufferGeometry(silhouette.shape);
    applyExplicitGeometryUvs(faceGeometry, silhouette.uvBounds);
    resources.push(faceGeometry);
    const face = new THREE.Mesh(faceGeometry, logoMaterial);
    face.name = 'uploadedLogoPendantFace';
    face.position.set(pendantOffsetX, -10, depth / 2 + HYPE_LOGO_FRONT_OFFSET);
    face.renderOrder = 3;
    face.castShadow = true;
    face.receiveShadow = true;
    face.frustumCulled = false;
    group.add(face);

    const hook = makeHypePendantHookMesh(silhouette, bodyMaterial, resources, depth);
    if (hook) {
      group.add(hook);
      alignHypeChainRigToPendantHook(hook);
    }

    updateHypeCameraFocus(group);
    renderHypeThree();
  };
  image.src = dataUrl;
}

function makeHypePendantHookMesh(silhouette, bodyMaterial, resources, depth) {
  const hookGeometry = state.hypeThree?.stlGeometries?.hook;
  if (!window.THREE) return null;
  if (!hookGeometry) {
    console.error('Pendant Hook STL geometry is missing; not rendering placeholder geometry.');
    return null;
  }
  const usableWidth = Math.max(1, silhouette.uvBounds?.width || 120);
  const desiredWidth = clamp(usableWidth * 0.2, 27, 34);
  const geometry = hookGeometry.clone();
  geometry.computeBoundingBox();
  const size = new THREE.Vector3();
  geometry.boundingBox.getSize(size);
  const hookMaterial = bodyMaterial.clone();
  hookMaterial.polygonOffset = true;
  hookMaterial.polygonOffsetFactor = -2;
  hookMaterial.polygonOffsetUnits = -2;
  resources.push(geometry, hookMaterial);

  const xyScale = desiredWidth / Math.max(size.x, 0.001);
  const zScale = (depth * 0.5) / Math.max(size.z, 0.001);
  const hookHeight = size.y * xyScale;
  const fuseOverlap = Math.min(30, hookHeight * 0.66);
  const hookAnchorY = Number.isFinite(silhouette.hookAnchorY)
    ? silhouette.hookAnchorY
    : (Number.isFinite(silhouette.centerTopY) ? silhouette.centerTopY : silhouette.topY);
  const fusedAnchorY = getHookFusedAnchorY(silhouette, hookAnchorY, desiredWidth, fuseOverlap);
  const extraDrop = Math.max(0, hookAnchorY - fusedAnchorY);
  const bodyTopY = -10 + fusedAnchorY;

  const hookGroup = new THREE.Group();
  hookGroup.name = 'uploadedLogoPendantHookAssembly';
  hookGroup.position.z = 0;
  hookGroup.userData.extraDrop = extraDrop;
  hookGroup.userData.shortLogoChainDrop = getShortLogoChainDrop(silhouette);

  const hook = new THREE.Mesh(geometry, hookMaterial);
  hook.name = 'uploadedLogoPendantHook';
  hook.scale.set(xyScale, xyScale, zScale);
  hook.position.set(0, bodyTopY + hookHeight / 2 - fuseOverlap - 4, 0);
  hook.renderOrder = 4;
  hook.castShadow = true;
  hook.receiveShadow = true;
  hook.frustumCulled = false;
  hookGroup.add(hook);
  console.info('Pendant Hook added to uploaded-logo pendant', {
    source: hookGeometry ? 'stl' : 'fallback',
    anchorY: Number(bodyTopY.toFixed(2)),
    anchorX: Number((silhouette.hookAnchorX || 0).toFixed(2)),
    extraDrop: Number(extraDrop.toFixed(2)),
    width: Number(desiredWidth.toFixed(2)),
    height: Number(hookHeight.toFixed(2)),
    shortLogoChainDrop: Number(hookGroup.userData.shortLogoChainDrop.toFixed(2)),
    zOffset: Number(hookGroup.position.z.toFixed(2)),
  });
  return hookGroup;
}

function alignHypeChainRigToPendantHook(hookGroup) {
  const chainRig = state.hypeThree?.group?.getObjectByName?.('hypeChainAttachmentRig');
  const attachmentLink = chainRig?.getObjectByName?.('pendantAttachmentLink');
  const hook = hookGroup?.getObjectByName?.('uploadedLogoPendantHook');
  if (!chainRig) return;
  chainRig.position.y = HYPE_UPLOADED_CHAIN_DROP_Y;
  if (!attachmentLink || !hook || !window.THREE) return;

  state.hypeThree.group.updateMatrixWorld(true);
  const hookBox = new THREE.Box3().setFromObject(hook);
  const linkBox = new THREE.Box3().setFromObject(attachmentLink);
  if (hookBox.isEmpty() || linkBox.isEmpty()) return;

  const hookHeight = Math.max(1, hookBox.max.y - hookBox.min.y);
  const hookHoleCenterY = hookBox.max.y - hookHeight * HYPE_HOOK_HOLE_CENTER_FROM_TOP;
  const linkBottomY = linkBox.min.y;
  const rigDeltaY = clamp(
    hookHoleCenterY - linkBottomY,
    -HYPE_HOOK_CHAIN_ALIGN_LIMIT,
    HYPE_HOOK_CHAIN_ALIGN_LIMIT,
  );
  const shortLogoChainDrop = clamp(Number(hookGroup.userData?.shortLogoChainDrop) || 0, 0, HYPE_SHORT_LOGO_CHAIN_DROP_MAX);
  chainRig.position.y += rigDeltaY - shortLogoChainDrop;
  chainRig.userData.hookAlignmentDeltaY = rigDeltaY;
  chainRig.userData.shortLogoChainDrop = shortLogoChainDrop;
}

function getShortLogoChainDrop(silhouette) {
  const bounds = silhouette?.uvBounds;
  const width = Math.max(1, Number(bounds?.width) || 1);
  const height = Math.max(1, Number(bounds?.height) || 1);
  const ratio = height / width;
  if (ratio >= HYPE_SHORT_LOGO_RATIO_THRESHOLD) return 0;
  const range = HYPE_SHORT_LOGO_RATIO_THRESHOLD - 0.32;
  const amount = clamp((HYPE_SHORT_LOGO_RATIO_THRESHOLD - ratio) / range, 0, 1);
  return amount * HYPE_SHORT_LOGO_CHAIN_DROP_MAX;
}

function getHookFusedAnchorY(silhouette, fallbackY, hookWidth, fuseOverlap) {
  const points = Array.isArray(silhouette?.points) ? silhouette.points : [];
  if (points.length < 3) return fallbackY;
  const anchorX = Number(silhouette.hookAnchorX) || 0;
  const contactInset = clamp(hookWidth * 0.34, 9, 13);
  const leftY = getSilhouetteTopYNearX(points, anchorX - contactInset, hookWidth * 0.18);
  const rightY = getSilhouetteTopYNearX(points, anchorX + contactInset, hookWidth * 0.18);
  const requiredY = Math.min(
    Number.isFinite(leftY) ? leftY : fallbackY,
    Number.isFinite(rightY) ? rightY : fallbackY,
  ) + fuseOverlap * 0.24;
  return Math.min(fallbackY, requiredY);
}

function getSilhouetteTopYNearX(points, x, radius) {
  const nearby = points.filter(([pointX]) => Math.abs(pointX - x) <= radius);
  if (nearby.length) return Math.max(...nearby.map(([, pointY]) => pointY));
  const sorted = [...points].sort((a, b) => Math.abs(a[0] - x) - Math.abs(b[0] - x)).slice(0, 8);
  return sorted.length ? Math.max(...sorted.map(([, pointY]) => pointY)) : NaN;
}

function makeHypePendantColourLayers(silhouette, resources) {
  const layers = [];
  const regionGroups = Array.isArray(state.hype.pendantRegionShapes) ? state.hype.pendantRegionShapes : [];
  if (!regionGroups.length || !window.THREE) return layers;
  const bounds = silhouette.uvBounds;
  const width = bounds.width;
  const height = bounds.height;
  regionGroups.forEach((region, regionIndex) => {
    if (!Array.isArray(region.components) || !region.components.length) return;
    const colourIndex = Number.isInteger(region.colourIndex) ? region.colourIndex : regionIndex;
    const material = new THREE.MeshStandardMaterial({
      color: normalizeHex(state.hype.pendantColours?.[colourIndex] || region.hex || '#ffffff'),
      roughness: 0.24,
      metalness: 0.1,
      side: THREE.FrontSide,
      polygonOffset: true,
      polygonOffsetFactor: -7 - regionIndex,
      polygonOffsetUnits: -7 - regionIndex,
    });
    resources.push(material);
    region.components.forEach((component) => {
      if (!Array.isArray(component) || component.length < 3) return;
      const shape = new THREE.Shape();
      component.forEach((point, index) => {
        const x = bounds.minX + (Number(point[0]) || 0) * width;
        const y = bounds.minY + (1 - (Number(point[1]) || 0)) * height;
        if (index === 0) shape.moveTo(x, y);
        else shape.lineTo(x, y);
      });
      shape.closePath();
      const geometry = new THREE.ShapeBufferGeometry(shape);
      resources.push(geometry);
      const mesh = new THREE.Mesh(geometry, material);
      mesh.name = `uploadedLogoPendantColourLayer-${regionIndex}`;
      mesh.renderOrder = 4 + regionIndex;
      mesh.castShadow = true;
      mesh.receiveShadow = true;
      mesh.frustumCulled = false;
      layers.push(mesh);
    });
  });
  return layers;
}

function makeAlphaSilhouettePendantShape(image, width, height) {
  const canvas = document.createElement('canvas');
  const maxSampleSize = 520;
  const imageAspect = Math.max(0.001, image.width / Math.max(1, image.height));
  const sampleWidth = imageAspect >= 1 ? maxSampleSize : Math.max(24, Math.round(maxSampleSize * imageAspect));
  const sampleHeight = imageAspect >= 1 ? Math.max(24, Math.round(maxSampleSize / imageAspect)) : maxSampleSize;
  canvas.width = sampleWidth;
  canvas.height = sampleHeight;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  ctx.clearRect(0, 0, sampleWidth, sampleHeight);
  ctx.drawImage(image, 0, 0, sampleWidth, sampleHeight);
  const data = ctx.getImageData(0, 0, sampleWidth, sampleHeight).data;
  const mask = new Uint8Array(sampleWidth * sampleHeight);
  for (let i = 0; i < mask.length; i += 1) {
    mask[i] = data[i * 4 + 3] > 20 ? 1 : 0;
  }
  const outline = buildExactAlphaSilhouette(mask, sampleWidth, sampleHeight);
  const points = outline.map(([x, y]) => [
    (x - 0.5) * width,
    -(y - 0.5) * height,
  ]);
  if (points.length < 12) {
    const shape = makeFallbackHypePendantShape(width, height);
    return {
      shape,
      topY: height / 2,
      centerTopY: height / 2,
      hookAnchorX: 0,
      hookAnchorY: height / 2,
      points: [],
      uvBounds: { minX: -width / 2, minY: -height / 2, width, height },
    };
  }
  const shape = new THREE.Shape();
  points.forEach(([x, y], index) => {
    if (index === 0) shape.moveTo(x, y);
    else shape.lineTo(x, y);
  });
  shape.closePath();
  const pointBounds = getPointArrayBounds(points);
  const centerTopY = getCenteredSilhouetteTopY(points, pointBounds);
  const hookAnchor = getSilhouetteHookAnchor(points, pointBounds);
  return {
    shape,
    topY: pointBounds.maxY,
    centerTopY,
    hookAnchorX: hookAnchor.x,
    hookAnchorY: hookAnchor.y,
    points,
    uvBounds: {
      minX: pointBounds.minX,
      minY: pointBounds.minY,
      width: Math.max(0.0001, pointBounds.maxX - pointBounds.minX),
      height: Math.max(0.0001, pointBounds.maxY - pointBounds.minY),
    },
  };
}

function getSilhouetteHookAnchor(points, bounds) {
  if (!Array.isArray(points) || !points.length || !bounds) return { x: 0, y: 0 };
  const width = Math.max(1, bounds.maxX - bounds.minX);
  const height = Math.max(1, bounds.maxY - bounds.minY);
  const topBand = points.filter(([, y]) => y >= bounds.maxY - height * 0.34);
  const candidates = topBand.length >= 4 ? topBand : points;
  const xs = candidates.map(([x]) => x).sort((a, b) => a - b);
  const trim = Math.floor(xs.length * 0.12);
  const trimmed = xs.slice(trim, Math.max(trim + 1, xs.length - trim));
  const minX = Math.min(...trimmed);
  const maxX = Math.max(...trimmed);
  const rawX = (minX + maxX) / 2;
  const maxShift = width * 0.28;
  const x = clamp(rawX, -maxShift, maxShift);
  const anchorBand = candidates.filter(([pointX]) => Math.abs(pointX - x) <= clamp(width * 0.11, 8, 18));
  const y = anchorBand.length
    ? Math.max(...anchorBand.map(([, pointY]) => pointY))
    : getCenteredSilhouetteTopY(points, bounds);
  return { x, y };
}

function getCenteredSilhouetteTopY(points, bounds) {
  if (!Array.isArray(points) || !points.length) return bounds?.maxY || 0;
  const width = Math.max(1, (bounds?.maxX || 0) - (bounds?.minX || 0));
  const centerBand = clamp(width * 0.09, 7, 16);
  const centered = points.filter(([x]) => Math.abs(x) <= centerBand);
  if (centered.length) return Math.max(...centered.map(([, y]) => y));
  return points.reduce((best, point) => (Math.abs(point[0]) < Math.abs(best[0]) ? point : best), points[0])[1];
}

function makeAlphaSilhouettePendantGeometry(shape, depth) {
  const geometry = new THREE.ExtrudeBufferGeometry(shape, {
    depth,
    bevelEnabled: true,
    bevelThickness: 0.35,
    bevelSize: 0.35,
    bevelSegments: 2,
    curveSegments: 6,
  });
  geometry.translate(0, 0, -depth / 2);
  geometry.computeBoundingSphere();
  geometry.computeVertexNormals();
  return geometry;
}

function buildExactAlphaSilhouette(mask, width, height) {
  const traced = traceMaskOutline(mask, width, height);
  if (traced.length >= 12) {
    const simplified = simplifyPolygon(traced, Math.max(0.18, Math.max(width, height) / 2400));
    return simplified.map(([x, y]) => [
      clamp(x / width, 0, 1),
      clamp(y / height, 0, 1),
    ]);
  }
  return buildSilhouette(mask, width, height);
}

function makeFallbackHypePendantBodyGeometry(width, height, depth) {
  const shape = makeFallbackHypePendantShape(width, height);
  const geometry = new THREE.ExtrudeBufferGeometry(shape, {
    depth,
    bevelEnabled: true,
    bevelThickness: 1.8,
    bevelSize: 1.8,
    bevelSegments: 4,
    curveSegments: 10,
  });
  geometry.center();
  geometry.computeBoundingSphere();
  geometry.computeVertexNormals();
  return geometry;
}

function makeFallbackHypePendantShape(width, height) {
  const shape = new THREE.Shape();
  roundedRectShape(shape, -width / 2, -height / 2, width, height, 16);
  return shape;
}

function makeHypeLogoPendantBail(topY, material, resources) {
  if (!window.THREE || !Number.isFinite(topY)) return null;
  const group = new THREE.Group();
  group.name = 'uploadedLogoPendantBail';
  const ringGeometry = new THREE.TorusBufferGeometry(7.2, 1.8, 14, 40);
  ringGeometry.rotateX(Math.PI / 2);
  resources.push(ringGeometry);
  const ring = new THREE.Mesh(ringGeometry, material);
  ring.position.set(0, topY + 4.2, 9.4);
  ring.castShadow = true;
  ring.receiveShadow = true;
  ring.frustumCulled = false;
  group.add(ring);
  return group;
}

function getPointArrayBounds(points) {
  return points.reduce((bounds, point) => ({
    minX: Math.min(bounds.minX, point[0]),
    maxX: Math.max(bounds.maxX, point[0]),
    minY: Math.min(bounds.minY, point[1]),
    maxY: Math.max(bounds.maxY, point[1]),
  }), {
    minX: Infinity,
    maxX: -Infinity,
    minY: Infinity,
    maxY: -Infinity,
  });
}

function applyExplicitGeometryUvs(geometry, bounds) {
  const position = geometry.attributes.position;
  const uvs = [];
  for (let i = 0; i < position.count; i += 1) {
    uvs.push(
      clamp((position.getX(i) - bounds.minX) / bounds.width, 0, 1),
      clamp((position.getY(i) - bounds.minY) / bounds.height, 0, 1),
    );
  }
  geometry.setAttribute('uv', new THREE.Float32BufferAttribute(uvs, 2));
}

function makeHypeSilkMaterial(hex) {
  return new THREE.MeshStandardMaterial({
    color: makeThreeColour(hex),
    roughness: 0.32,
    metalness: 0.24,
    envMapIntensity: 0.55,
  });
}

function mergeBufferGeometriesAsOne(geometries) {
  const expanded = geometries.map((geometry) => (geometry.index ? geometry.toNonIndexed() : geometry.clone()));
  const attributes = ['position', 'normal', 'uv'];
  const merged = new THREE.BufferGeometry();
  attributes.forEach((name) => {
    const sourceAttributes = expanded
      .map((geometry) => geometry.getAttribute(name))
      .filter(Boolean);
    if (!sourceAttributes.length) return;
    const itemSize = sourceAttributes[0].itemSize;
    const count = sourceAttributes.reduce((total, attr) => total + attr.count * itemSize, 0);
    const array = new Float32Array(count);
    let offset = 0;
    sourceAttributes.forEach((attr) => {
      array.set(attr.array, offset);
      offset += attr.array.length;
    });
    merged.setAttribute(name, new THREE.BufferAttribute(array, itemSize));
  });
  expanded.forEach((geometry) => geometry.dispose());
  return merged;
}

function makeRoundedRectangleTubeGeometry(width, height, radius, tubeRadius) {
  const points = makeRoundedRectanglePoints(width, height, radius, 8);
  const curve = new THREE.CatmullRomCurve3(points, true, 'centripetal', 0.5);
  return new THREE.TubeBufferGeometry(curve, 96, tubeRadius, 18, true);
}

function makeRoundedRectanglePoints(width, height, radius, segments = 8) {
  const hw = width / 2 - radius;
  const hh = height / 2 - radius;
  const corners = [
    { cx: hw, cy: hh, start: 0 },
    { cx: -hw, cy: hh, start: Math.PI / 2 },
    { cx: -hw, cy: -hh, start: Math.PI },
    { cx: hw, cy: -hh, start: Math.PI * 1.5 },
  ];
  const points = [];
  corners.forEach((corner) => {
    for (let i = 0; i <= segments; i += 1) {
      const angle = corner.start + (i / segments) * (Math.PI / 2);
      points.push(new THREE.Vector3(
        corner.cx + Math.cos(angle) * radius,
        corner.cy + Math.sin(angle) * radius,
        0,
      ));
    }
  });
  return points;
}

function roundedRectShape(shape, x, y, w, h, r) {
  shape.moveTo(x + r, y);
  shape.lineTo(x + w - r, y);
  shape.quadraticCurveTo(x + w, y, x + w, y + r);
  shape.lineTo(x + w, y + h - r);
  shape.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  shape.lineTo(x + r, y + h);
  shape.quadraticCurveTo(x, y + h, x, y + h - r);
  shape.lineTo(x, y + r);
  shape.quadraticCurveTo(x, y, x + r, y);
}

function renderHypeLinks() {
  if (!els.hypeChainOval) return;
  const hype = state.hype;
  const linkCount = getHypeLinkCount(hype.chainLength, hype.linkCount);
  const colours = getHypePatternColours();
  const sideCount = Math.max(7, Math.floor((linkCount + 4) / 2));
  const links = [];
  for (let side = 0; side < 2; side += 1) {
    const isLeft = side === 0;
    for (let i = 0; i < sideCount; i += 1) {
      const t = sideCount === 1 ? 0 : i / (sideCount - 1);
      const curve = Math.sin(t * Math.PI);
      const xOuter = isLeft ? 29 : 71;
      const xInner = isLeft ? 45 : 55;
      const x = xOuter + (xInner - xOuter) * t + (isLeft ? -1 : 1) * curve * 2;
      const y = 0 + t * 78 + Math.sin(t * Math.PI * 0.76) * 12;
      const lean = (isLeft ? -1 : 1) * (28 - t * 16);
      const twist = ((i % 3) - 1) * 4;
      const perpendicular = i % 2 === 1;
      const colour = colours[(i + (isLeft ? 0 : 1)) % colours.length];
      const z = 18 + (perpendicular ? 34 : 4) + (sideCount - i) * 0.75;
      links.push(`<span class="hype-link ${perpendicular ? 'perpendicular' : 'face'} ${isLeft ? 'left' : 'right'}" style="--x:${x.toFixed(2)}%;--y:${y.toFixed(2)}%;--rot:${(lean + twist).toFixed(2)}deg;--link-color:${colour};--link-z:${z.toFixed(2)}px;--link-order:${i};"></span>`);
    }
  }
  els.hypeChainOval.innerHTML = links.join('');
}

function getHypeSpecLabel() {
  const variant = state.hype.variant === 'spinner' ? 'Spinner' : 'Classic';
  return `${variant} - ${normalizeHypeChainLength(state.hype.chainLength)}`;
}

function renderHypeColourControls() {
  syncHypeDerivedColours();
  const patternLength = getHypePatternLength();
  const hasLogoPendant = Boolean(state.hype.logoDataUrl);
  const labels = {
    primary: 'Primary',
    secondary: 'Secondary',
    tertiary: 'Tertiary',
    pendant: 'Pendant',
    pendantCasing: 'Pendant casing',
  };
  const visibleKeys = new Set(['primary']);
  if (patternLength >= 2) visibleKeys.add('secondary');
  if (patternLength >= 3) visibleKeys.add('tertiary');
  els.hypeColourButtons.forEach((button) => {
    const key = button.dataset.hypeColour;
    const visible = key === 'pendant' ? hasLogoPendant : visibleKeys.has(key);
    button.hidden = !visible;
    button.style.display = visible ? '' : 'none';
    const hex = normalizeHex(state.hype[key] || '#ffffff');
    const dot = button.querySelector('i');
    const label = button.querySelector('span');
    if (dot) dot.style.background = hex;
    if (label) label.textContent = labels[key] || key;
    button.setAttribute('aria-label', `${labels[key] || key} colour ${hex}`);
  });
  els.hypePendantColourSection?.classList.toggle('hidden', !hasLogoPendant);
  if (els.hypePendantColourRow) {
    if (!hasLogoPendant) {
      els.hypePendantColourRow.innerHTML = '';
    } else {
      const colours = getHypePendantColours();
      const casingHex = getHypePendantBodyColour();
      const casingButton = `
        <button class="hype-colour-chip hype-casing-colour-chip" type="button" data-hype-pendant-casing aria-label="Pendant backing sides and hook colour ${casingHex}" title="Pendant backing, sides, and hook">
          <i data-pendant-casing-colour="${casingHex}" style="background:${casingHex}"></i>
        </button>
      `;
      const logoButtons = colours.length
        ? colours.map((hex, index) => {
          const label = getHypePendantColourLabel(index);
          return `
            <button class="hype-colour-chip" type="button" data-hype-pendant-colour="${index}" aria-label="Pendant colour ${label} ${hex}">
              <i data-pendant-colour="${hex}" style="background:${hex}"></i>
            </button>
          `;
        }).join('')
        : '<span class="used-empty">Upload logo colours will appear here.</span>';
      els.hypePendantColourRow.innerHTML = casingButton + logoButtons;
      els.hypePendantColourRow.querySelector('[data-hype-pendant-casing]')?.addEventListener('click', (event) => {
        openHypeColourPopover('pendantCasing', event.currentTarget);
        setPopoverTab('used');
      });
      els.hypePendantColourRow.querySelectorAll('[data-hype-pendant-colour]').forEach((button) => {
        button.addEventListener('click', () => openHypePendantColourPopover(Number(button.dataset.hypePendantColour), button));
      });
    }
  }
}

function getDefaultHypeLinkCount(chainLength) {
  return normalizeHypeChainLength(chainLength) === 'Youth' ? 25 : 27;
}

function normalizeHypeLinkCount(value) {
  return clamp(Math.round(Number(value) || 27), 25, 27);
}

function getHypeLinkCount(chainLength, explicitCount) {
  return normalizeHypeLinkCount(explicitCount || getDefaultHypeLinkCount(chainLength));
}

function normalizeHypeChainLength(chainLength) {
  if (chainLength === 'Short' || chainLength === 'Children' || chainLength === 'Youth') return 'Youth';
  return 'Adult';
}

function getHypePatternLength(value = state.hype.patternLength) {
  return clamp(Math.round(Number(value) || 2), 1, 3);
}

function syncHypeDerivedColours() {
  state.hype.patternLength = getHypePatternLength();
  state.hype.primary = normalizeHex(state.hype.primary || '#111111');
  state.hype.secondary = normalizeHex(state.hype.secondary || '#ffc529');
  state.hype.tertiary = normalizeHex(state.hype.tertiary || '#ffffff');
  state.hype.pendant = normalizeHex(state.hype.pendant || '#202326');
  state.hype.pendantCasing = normalizeHex(state.hype.pendantCasing || state.hype.pendant || '#202326');
  state.hype.pendantSourceColours = (state.hype.pendantSourceColours || []).map((hex) => normalizeHex(hex));
  state.hype.pendantColours = (state.hype.pendantColours || []).map((hex) => normalizeHex(hex));
  state.hype.pendantColourLabels = Array.isArray(state.hype.pendantColourLabels) ? state.hype.pendantColourLabels : [];
  state.hype.accent = state.hype.primary;
  state.hype.border = state.hype.primary;
  state.hype.chainLength = normalizeHypeChainLength(state.hype.chainLength);
  state.hype.linkCount = getDefaultHypeLinkCount(state.hype.chainLength);
}

function getHypePendantColours() {
  const sourceColours = state.hype.pendantSourceColours || [];
  if (!sourceColours.length) return [];
  if (!Array.isArray(state.hype.pendantColours)) state.hype.pendantColours = [];
  state.hype.pendantColours = sourceColours.map((sourceHex, index) => normalizeHex(state.hype.pendantColours[index] || sourceHex));
  return state.hype.pendantColours;
}

function getHypePendantColourLabel(index) {
  return state.hype.pendantColourLabels?.[index] || String(index + 1);
}

function getHypePatternColours() {
  syncHypeDerivedColours();
  const colours = [state.hype.primary];
  if (state.hype.patternLength >= 2) colours.push(state.hype.secondary);
  if (state.hype.patternLength >= 3) colours.push(state.hype.tertiary);
  return colours.map((hex) => normalizeHex(hex));
}

function applyHypePendantColoursToChain() {
  const fallback = ['#d6001c', '#0057b8', '#ffc529'];
  const ranked = getRankedPendantChainColours();
  const colours = uniqueHexColours(ranked.map((item) => item.hex));
  const chainColours = [0, 1, 2].map((index) => normalizeHex(colours[index] || fallback[index]));
  state.hype.primary = chainColours[0];
  if (getHypePatternLength() >= 2) state.hype.secondary = chainColours[1];
  if (getHypePatternLength() >= 3) state.hype.tertiary = chainColours[2];
  syncHypeDerivedColours();
  applyHypeStateToControls();
  renderHypeColourControls();
}

function getRankedPendantChainColours() {
  const processedColours = (state.processed?.colours || []).map((region, index) => ({
    hex: normalizeHex(getDisplayColour(index, region.hex)),
    count: Number(region.count) || 0,
  }));
  const fallbackColours = getHypePendantColours().map((hex) => ({ hex: normalizeHex(hex), count: 1 }));
  const combined = uniqueHexColours((processedColours.length ? processedColours : fallbackColours).map((item) => item.hex))
    .map((hex) => {
      const source = [...processedColours, ...fallbackColours].find((item) => normalizeHex(item.hex) === hex) || { count: 1 };
      const rgb = hexToRgb(hex);
      const luma = colourLuma(rgb);
      const saturation = colourChroma(rgb);
      const isNeutral = saturation < 34 || luma <= 34 || luma >= 224;
      const prominence = Math.sqrt(Math.max(1, source.count));
      const contrast = Math.abs(luma - 128);
      return {
        hex,
        isNeutral,
        score: (isNeutral ? 0 : 260) + saturation * 3.2 + prominence * 0.42 + contrast * 0.18,
        neutralScore: prominence * 0.5 + contrast * 0.35,
      };
    });
  const accents = combined
    .filter((item) => !item.isNeutral)
    .sort((a, b) => b.score - a.score);
  const neutrals = combined
    .filter((item) => item.isNeutral)
    .sort((a, b) => b.neutralScore - a.neutralScore);
  return [...accents, ...neutrals];
}

function applyHypeStateToControls() {
  document.querySelectorAll('[data-hype-variant]').forEach((button) => {
    button.classList.toggle('active', button.dataset.hypeVariant === state.hype.variant);
  });
  renderHypeVariantAccess();
  if (els.hypePrimaryColour) els.hypePrimaryColour.value = normalizeHex(state.hype.primary);
  if (els.hypeSecondaryColour) els.hypeSecondaryColour.value = normalizeHex(state.hype.secondary);
  if (els.hypeTertiaryColour) els.hypeTertiaryColour.value = normalizeHex(state.hype.tertiary);
  if (els.hypeAccentColour) els.hypeAccentColour.value = normalizeHex(state.hype.primary);
  if (els.hypePendantColour) els.hypePendantColour.value = getHypePendantBodyColour();
  if (els.hypeBorderColour) els.hypeBorderColour.value = normalizeHex(state.hype.primary);
  if (els.hypePendantText) els.hypePendantText.value = state.hype.text;
  if (els.hypePatternLength) els.hypePatternLength.value = String(getHypePatternLength());
  if (els.hypeChainLength) els.hypeChainLength.value = state.hype.chainLength;
  if (els.hypeQuantity) els.hypeQuantity.value = String(state.hype.quantity);
  renderHypeColourControls();
}

function renderHypeVariantAccess() {
  document.querySelectorAll('[data-hype-variant]').forEach((button) => {
    const locked = button.dataset.hypeVariant === 'spinner' && !state.isAdmin;
    button.classList.toggle('locked', locked);
    button.setAttribute('aria-disabled', locked ? 'true' : 'false');
    if (locked) {
      button.setAttribute('aria-describedby', 'spinnerLockTooltip');
      if (state.hype.variant === 'spinner') state.hype.variant = 'classic';
    } else {
      button.removeAttribute('aria-describedby');
    }
    const lock = button.querySelector('.spinner-lock');
    if (lock) lock.hidden = !locked;
    button.classList.toggle('active', button.dataset.hypeVariant === state.hype.variant);
  });
}

function setupHypeDrag() {
  if (!els.hypePreview || !els.hypeChainRender) return;
  let dragging = false;
  let lastX = 0;
  let lastY = 0;
  let activePointerId = null;
  let velocityX = 0;
  let velocityY = 0;
  const stop = () => {
    if (!dragging) return;
    dragging = false;
    activePointerId = null;
    els.hypeChainRender.classList.remove('dragging');
    velocityX = 0;
    velocityY = 0;
  };
  els.hypePreview.addEventListener('pointerdown', (event) => {
    if (state.productType !== 'hype') return;
    if (state.previewTouchGestureActive || (event.pointerType === 'touch' && event.isPrimary === false)) return;
    if (event.pointerType === 'mouse' && Number.isFinite(event.button) && event.button > 0) return;
    event.preventDefault();
    event.stopPropagation();
    dragging = true;
    activePointerId = event.pointerId;
    lastX = event.clientX;
    lastY = event.clientY;
    velocityX = 0;
    velocityY = 0;
    els.hypeChainRender.classList.add('dragging');
    els.hypePreview.setPointerCapture(event.pointerId);
  });
  const move = (event) => {
    if (!dragging) return;
    if (state.previewTouchGestureActive) {
      stop();
      return;
    }
    if (activePointerId !== null && event.pointerId !== undefined && event.pointerId !== activePointerId) return;
    if (event.pointerType === 'mouse' && event.buttons && !(event.buttons & 1)) {
      stop();
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    const dx = event.clientX - lastX;
    const dy = event.clientY - lastY;
    lastX = event.clientX;
    lastY = event.clientY;
    velocityX = dx * 0.42;
    velocityY = dy * 0.36;
    state.hype.rotation.y += velocityX;
    state.hype.rotation.x -= velocityY;
    updateHypeCssRotation();
    updateHypeThreeRotation();
  };
  els.hypePreview.addEventListener('pointermove', move);
  els.hypePreview.addEventListener('pointerup', stop);
  els.hypePreview.addEventListener('pointercancel', stop);
  els.hypePreview.addEventListener('lostpointercapture', stop);
  els.hypePreview.addEventListener('contextmenu', (event) => {
    if (state.productType !== 'hype') return;
    event.preventDefault();
  });
  window.addEventListener('pointerup', stop);
  window.addEventListener('pointercancel', stop);
}

function normalizeDegrees(value) {
  return ((((Number(value) || 0) + 180) % 360) + 360) % 360 - 180;
}

function openAdminGate() {
  if (!els.adminGate || !els.adminPassword) return;
  els.adminGate.classList.remove('hidden', 'invalid');
  if (els.adminGateError) els.adminGateError.textContent = '';
  els.adminPassword.value = '';
  window.setTimeout(() => els.adminPassword.focus(), 0);
}

function closeAdminGate() {
  els.adminGate?.classList.add('hidden');
}

async function loginAdmin() {
  const password = els.adminPassword?.value || '';
  if (!password.trim()) {
    showAdminLoginError('Enter the admin password.');
    return;
  }
  try {
    const ok = await verifyAdminPassword(password);
    if (!ok) {
      showAdminLoginError('Incorrect admin password.');
      return;
    }
    state.isAdmin = true;
    sessionStorage.setItem(ADMIN_SESSION_KEY, 'true');
    closeAdminGate();
    renderAdminMode();
    setStatus('Admin mode');
  } catch (error) {
    console.error(error);
    showAdminLoginError('Admin login is unavailable.');
  }
}

function logoutAdmin() {
  state.isAdmin = false;
  sessionStorage.removeItem(ADMIN_SESSION_KEY);
  renderAdminMode();
  setStatus('Ready');
}

function showAdminLoginError(message) {
  els.adminGate?.classList.add('invalid');
  if (els.adminGateError) els.adminGateError.textContent = message;
  els.adminPassword?.focus();
}

async function verifyAdminPassword(password) {
  if (isLocalTesting()) {
    const localPassword = window.SIGN_GUY_LOCAL_ADMIN_PASSWORD || LOCAL_ADMIN_PASSWORD;
    return password === localPassword;
  }
  const endpoint = getAdminLoginEndpoint();
  if (!endpoint) return false;
  const response = await fetch(endpoint, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ password }),
  });
  return response.ok;
}

function getAdminLoginEndpoint() {
  if (window.SIGN_GUY_ADMIN_LOGIN_ENDPOINT) return window.SIGN_GUY_ADMIN_LOGIN_ENDPOINT;
  if (!window.location.protocol.startsWith('http')) return '';
  return new URL('/api/admin-login', window.location.href).href;
}

function renderUploadControl() {
  if (!els.chooseFileText) return;
  els.chooseFileText.textContent = state.uploadedFile ? 'Choose a different logo' : 'Upload logo';
}

function setupDropZone(zone = els.dropZone, onDrop = (files) => handleFiles(files)) {
  if (!zone) return;
  ['dragenter', 'dragover'].forEach((eventName) => {
    zone.addEventListener(eventName, (event) => {
      event.preventDefault();
      zone.classList.add('dragging');
    });
  });
  ['dragleave', 'drop'].forEach((eventName) => {
    zone.addEventListener(eventName, (event) => {
      event.preventDefault();
      zone.classList.remove('dragging');
    });
  });
  zone.addEventListener('drop', (event) => onDrop(event.dataTransfer.files));
}

function setupFileButtonKeyboard(label, input) {
  if (!label || !input) return;
  label.addEventListener('keydown', (event) => {
    if (event.key !== 'Enter' && event.key !== ' ') return;
    event.preventDefault();
    input.click();
  });
}

function setupDragRotation() {
  let dragging = false;
  let start = null;
  els.stage.addEventListener('pointerdown', (event) => {
    if (state.previewTouchGestureActive || (event.pointerType === 'touch' && event.isPrimary === false)) return;
    if (event.target.closest('.hype-preview')) return;
    if (event.target.closest('button, label, input, .preview-alert')) return;
    event.preventDefault();
    dragging = true;
    start = { x: event.clientX, y: event.clientY, rx: state.rotation.x, ry: state.rotation.y };
    els.stage.setPointerCapture(event.pointerId);
  });
  els.stage.addEventListener('pointermove', (event) => {
    if (!dragging) return;
    if (state.previewTouchGestureActive) {
      dragging = false;
      return;
    }
    event.preventDefault();
    state.rotation.x = clamp(start.rx - (event.clientY - start.y) * 0.24, -58, 58);
    state.rotation.y = start.ry + (event.clientX - start.x) * 0.42;
    applyRotation();
  });
  const stopDrag = () => {
    dragging = false;
  };
  els.stage.addEventListener('pointerup', stopDrag);
  els.stage.addEventListener('pointercancel', stopDrag);
  els.stage.addEventListener('lostpointercapture', stopDrag);
}

function setupPreviewTouchGestures() {
  if (!els.stage) return;
  let gesture = null;
  const getTouches = (event) => [...event.touches].slice(0, 2);
  const getDistance = ([first, second]) => Math.hypot(second.clientX - first.clientX, second.clientY - first.clientY);
  const getMidpoint = ([first, second]) => ({
    x: (first.clientX + second.clientX) / 2,
    y: (first.clientY + second.clientY) / 2,
  });
  const startGesture = (event) => {
    if (event.touches.length < 2 || event.target.closest('button, label, input, select, textarea, .preview-alert')) return;
    const touches = getTouches(event);
    const midpoint = getMidpoint(touches);
    gesture = {
      distance: Math.max(1, getDistance(touches)),
      midpoint,
      zoom: state.previewZoom,
      pan: { ...getPreviewPan() },
    };
    state.previewTouchGestureActive = true;
    event.preventDefault();
  };
  els.stage.addEventListener('touchstart', startGesture, { passive: false });
  els.stage.addEventListener('touchmove', (event) => {
    if (!gesture || event.touches.length < 2) return;
    const touches = getTouches(event);
    const midpoint = getMidpoint(touches);
    const distance = Math.max(1, getDistance(touches));
    const nextZoom = gesture.zoom * (distance / gesture.distance);
    const nextPan = {
      x: gesture.pan.x + midpoint.x - gesture.midpoint.x,
      y: gesture.pan.y + midpoint.y - gesture.midpoint.y,
    };
    event.preventDefault();
    setPreviewZoom(nextZoom, { render: false });
    setPreviewPan(nextPan.x, nextPan.y, { render: true });
  }, { passive: false });
  const stopGesture = () => {
    if (!gesture && !state.previewTouchGestureActive) return;
    gesture = null;
    window.setTimeout(() => {
      state.previewTouchGestureActive = false;
    }, 60);
  };
  els.stage.addEventListener('touchend', (event) => {
    if (event.touches.length < 2) stopGesture();
  });
  els.stage.addEventListener('touchcancel', stopGesture);
}

function setupProjectAccordion() {
  if (!els.projectSection || !els.projectSectionHeading) return;
  const toggle = () => {
    const expanded = els.projectSection.classList.toggle('mobile-expanded');
    els.projectSection.classList.toggle('mobile-collapsed', !expanded);
    els.projectSectionHeading.setAttribute('aria-expanded', expanded ? 'true' : 'false');
  };
  els.projectSectionHeading.addEventListener('click', toggle);
  els.projectSectionHeading.addEventListener('keydown', (event) => {
    if (event.key !== 'Enter' && event.key !== ' ') return;
    event.preventDefault();
    toggle();
  });
}

async function handleFiles(fileList, options = {}) {
  const file = fileList?.[0];
  if (!file) return;
  const isSvg = file.type.includes('svg') || file.name.toLowerCase().endsWith('.svg');
  const isPng = file.type.includes('png') || file.name.toLowerCase().endsWith('.png');
  if (!isSvg && !isPng) {
    setStatus('Unsupported');
    setWarnings([{ level: 'error', text: 'Please upload an SVG or PNG file.' }]);
    return;
  }

  const target = options.target === 'hype' ? 'hype' : 'led';
  state.uploadTarget = target;
  if (target === 'hype') state.ledUploadSnapshot = captureLedUploadState();

  setStatus('Importing');
  state.isDefaultPreview = false;
  state.fileName = file.name;
  state.designName = '';
  els.designName.value = '';
  state.uploadedFile = file;
  renderUploadControl();
  state.projectId = null;
  try {
    state.artwork = isSvg ? await readSvgArtwork(file) : await readPngArtwork(file);
    state.removeBg = state.artwork.hasTransparency ? false : true;
    els.removeBg.checked = state.removeBg;
    state.fixFloatingRegions = false;
    state.floatingSupportColour = DEFAULT_FLOATING_SUPPORT_COLOUR;
    state.targetColorCount = 8;
    state.colorOverrides = [];
    state.frontColoursCustomized = false;
    state.selectedColor = 0;
    state.selectedColourTarget = { type: 'front', index: 0 };
    state.previewZoom = 1;
    state.previewPan = { x: 0, y: 0 };
    state.dismissedPreviewAlert = '';
    resetRotation();
    initEditState(state.artwork);
    await reprocess();
    openWizard('edit');
  } catch (error) {
    if (target === 'hype') restoreLedUploadState();
    console.error(error);
    setStatus('Import failed');
    setWarnings([{ level: 'error', text: error.message || 'The artwork could not be imported.' }]);
  }
}

function captureLedUploadState() {
  return {
    fileName: state.fileName,
    designName: state.designName,
    isDefaultPreview: state.isDefaultPreview,
    uploadedFile: state.uploadedFile,
    artwork: state.artwork,
    processed: state.processed,
    removeBg: state.removeBg,
    fixFloatingRegions: state.fixFloatingRegions,
    floatingSupportColour: state.floatingSupportColour,
    tolerance: state.tolerance,
    targetColorCount: state.targetColorCount,
    colorOverrides: [...state.colorOverrides],
    frontColoursCustomized: state.frontColoursCustomized,
    selectedColor: state.selectedColor,
    selectedColourTarget: { ...state.selectedColourTarget },
    projectId: state.projectId,
    edit: {
      crop: { ...state.edit.crop },
      cropAspect: state.edit.cropAspect,
      zoom: state.edit.zoom,
    },
    previewZoom: state.previewZoom,
    previewPan: { ...getPreviewPan() },
    dismissedPreviewAlert: state.dismissedPreviewAlert,
    rotation: { ...state.rotation },
  };
}

function restoreLedUploadState() {
  const snapshot = state.ledUploadSnapshot;
  if (!snapshot) return;
  Object.assign(state, {
    fileName: snapshot.fileName,
    designName: snapshot.designName,
    isDefaultPreview: snapshot.isDefaultPreview,
    uploadedFile: snapshot.uploadedFile,
    artwork: snapshot.artwork,
    processed: snapshot.processed,
    removeBg: snapshot.removeBg,
    fixFloatingRegions: snapshot.fixFloatingRegions,
    floatingSupportColour: snapshot.floatingSupportColour,
    tolerance: snapshot.tolerance,
    targetColorCount: snapshot.targetColorCount,
    colorOverrides: [...snapshot.colorOverrides],
    frontColoursCustomized: snapshot.frontColoursCustomized,
    selectedColor: snapshot.selectedColor,
    selectedColourTarget: { ...snapshot.selectedColourTarget },
    projectId: snapshot.projectId,
    edit: {
      crop: { ...snapshot.edit.crop },
      cropAspect: snapshot.edit.cropAspect,
      zoom: snapshot.edit.zoom,
    },
    previewZoom: snapshot.previewZoom,
    previewPan: { ...(snapshot.previewPan || { x: 0, y: 0 }) },
    dismissedPreviewAlert: snapshot.dismissedPreviewAlert,
    rotation: { ...snapshot.rotation },
  });
  if (els.designName) els.designName.value = state.designName;
  if (els.removeBg) els.removeBg.checked = state.removeBg;
  renderUploadControl();
  if (state.processed) renderPreview();
  state.ledUploadSnapshot = null;
  state.uploadTarget = 'led';
}

async function readSvgArtwork(file) {
  const text = await file.text();
  const parser = new DOMParser();
  const documentSvg = parser.parseFromString(text, 'image/svg+xml');
  if (documentSvg.querySelector('parsererror')) throw new Error('The SVG could not be parsed.');
  const normalizedText = normalizeSvgForImage(documentSvg);
  const gradients = documentSvg.querySelectorAll('linearGradient, radialGradient').length;
  const pathCount = documentSvg.querySelectorAll('path, polygon, polyline, rect, circle, ellipse').length;
  const palette = extractSvgPalette(documentSvg);
  const blob = new Blob([normalizedText], { type: 'image/svg+xml' });
  const url = URL.createObjectURL(blob);
  const image = await loadImage(url);
  URL.revokeObjectURL(url);
  const dataUrl = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(normalizedText)}`;
  return { type: 'svg', image, dataUrl, pathCount, gradients, palette, hasTransparency: imageHasTransparency(image), name: file.name };
}

function normalizeSvgForImage(documentSvg) {
  const svg = documentSvg.documentElement;
  if (!svg) return new XMLSerializer().serializeToString(documentSvg);
  const width = parseSvgLength(svg.getAttribute('width'));
  const height = parseSvgLength(svg.getAttribute('height'));
  const viewBox = parseViewBox(svg.getAttribute('viewBox'));
  const fallbackWidth = viewBox ? Math.abs(viewBox[2]) : 1024;
  const fallbackHeight = viewBox ? Math.abs(viewBox[3]) : fallbackWidth;
  if (!width || !height) {
    svg.setAttribute('width', String(Math.max(1, Math.round(width || fallbackWidth))));
    svg.setAttribute('height', String(Math.max(1, Math.round(height || fallbackHeight))));
  }
  if (!svg.getAttribute('preserveAspectRatio')) {
    svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
  }
  return new XMLSerializer().serializeToString(documentSvg);
}

function parseSvgLength(value) {
  if (!value) return null;
  const match = String(value).trim().match(/^([0-9]*\.?[0-9]+)/);
  return match ? Number(match[1]) : null;
}

function parseViewBox(value) {
  if (!value) return null;
  const parts = String(value).trim().split(/[\s,]+/).map(Number);
  return parts.length === 4 && parts.every(Number.isFinite) ? parts : null;
}

async function readPngArtwork(file) {
  const url = URL.createObjectURL(file);
  const dataUrl = await readAsDataUrl(file);
  const image = await loadImage(url);
  URL.revokeObjectURL(url);
  return { type: 'png', image, dataUrl, pathCount: 0, gradients: 0, hasTransparency: imageHasTransparency(image), name: file.name };
}

function imageHasTransparency(image) {
  const canvas = document.createElement('canvas');
  const width = Math.min(80, image.naturalWidth);
  const height = Math.min(80, image.naturalHeight);
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  ctx.clearRect(0, 0, width, height);
  ctx.drawImage(image, 0, 0, width, height);
  const data = ctx.getImageData(0, 0, width, height).data;
  for (let i = 3; i < data.length; i += 4) {
    if (data[i] < 250) return true;
  }
  return false;
}

function readAsDataUrl(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = () => reject(new Error('The image file could not be read.'));
    reader.readAsDataURL(file);
  });
}

function blobToDataUrl(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = () => reject(new Error('The file could not be read.'));
    reader.readAsDataURL(blob);
  });
}

function fileToDataUrl(file) {
  return blobToDataUrl(file);
}

function dataUrlToFile(dataUrl, filename) {
  const blob = dataUrlToBlob(dataUrl);
  try {
    return new File([blob], filename || 'lightbox-logo', { type: blob.type || 'application/octet-stream' });
  } catch {
    blob.name = filename || 'lightbox-logo';
    return blob;
  }
}

function dataUrlToBlob(dataUrl) {
  const [header, payload = ''] = String(dataUrl).split(',');
  const mime = header.match(/^data:([^;,]+)/)?.[1] || 'application/octet-stream';
  const isBase64 = /;base64/i.test(header);
  const binary = isBase64 ? atob(payload) : decodeURIComponent(payload);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
  return new Blob([bytes], { type: mime });
}

function inferArtworkType(dataUrl, filename = '') {
  const raw = `${dataUrl} ${filename}`.toLowerCase();
  return raw.includes('image/svg') || raw.includes('.svg') ? 'svg' : 'png';
}

function loadImage(src) {
  return new Promise((resolve, reject) => {
    const image = new Image();
    image.onload = () => resolve(image);
    image.onerror = () => reject(new Error('The image could not be loaded.'));
    image.src = src;
  });
}

function extractSvgPalette(documentSvg) {
  const values = [];
  documentSvg.querySelectorAll('style').forEach((node) => {
    [...(node.textContent || '').matchAll(/(?:fill|stroke)\s*:\s*([^;}\n]+)/gi)].forEach((match) => values.push(match[1]));
  });
  documentSvg.querySelectorAll('*').forEach((node) => {
    ['fill', 'stroke'].forEach((attr) => {
      const value = node.getAttribute(attr);
      if (value) values.push(value);
    });
    const style = node.getAttribute('style') || '';
    [...style.matchAll(/(?:fill|stroke)\s*:\s*([^;]+)/gi)].forEach((match) => values.push(match[1]));
  });
  const colours = [];
  values.forEach((value) => {
    const rgb = parseCssColour(value);
    if (!rgb) return;
    if (!colours.some((colour) => colourDistance(colour, rgb) < 4)) colours.push(rgb);
  });
  return colours.slice(0, 24);
}

function parseCssColour(value) {
  const raw = value.trim().toLowerCase();
  if (!raw || raw === 'none' || raw === 'transparent' || raw === 'currentcolor' || raw.startsWith('url(')) return null;
  const canvas = parseCssColour.canvas || (parseCssColour.canvas = document.createElement('canvas').getContext('2d'));
  canvas.fillStyle = '#000000';
  canvas.fillStyle = raw;
  const normalized = canvas.fillStyle;
  const hex = normalized.startsWith('#') ? normalized : null;
  if (!hex || hex === '#000000' && raw !== '#000' && raw !== '#000000' && raw !== 'black' && !raw.startsWith('rgb(0')) return null;
  if (hex.length === 7) {
    return [parseInt(hex.slice(1, 3), 16), parseInt(hex.slice(3, 5), 16), parseInt(hex.slice(5, 7), 16)];
  }
  return null;
}

async function reprocess(options = {}) {
  if (!state.artwork) return;
  setStatus('Processing');
  els.stage.classList.add('regenerating');
  const previousColourSnapshot = state.processed?.colours?.map((region, idx) => ({
    hex: normalizeHex(region.hex),
    display: normalizeHex(state.colorOverrides[idx] || region.hex),
    isFloatingSupport: Boolean(region.isFloatingSupport),
  })) || null;
  await waitFrame();
  try {
    state.processed = processArtwork(state.artwork);
    state.processingDirty = false;
    if (!options.preserveTargetColorCount && !state.frontColoursCustomized && state.processed.naturalColourCount) {
      state.targetColorCount = state.processed.naturalColourCount;
    }
    syncColorOverrides(previousColourSnapshot);
    renderPreview();
    renderDiagnostics();
    if (els.submitDesign) els.submitDesign.disabled = state.isDefaultPreview || !state.uploadedFile;
    updateProjectControls();
    setStatus('Ready');
    if (state.wizardStep && !options.skipWizardRender) renderWizardStep();
  } finally {
    requestAnimationFrame(() => els.stage.classList.remove('regenerating'));
  }
}

async function loadDefaultPreview() {
  try {
    const defaultType = 'svg';
    state.isDefaultPreview = true;
    state.uploadedFile = null;
    state.projectId = null;
    state.fileName = '';
    renderUploadControl();
    const image = await loadImage(DEFAULT_PREVIEW_DATA_URL);
    const artwork = {
      type: defaultType,
      image,
      dataUrl: DEFAULT_PREVIEW_DATA_URL,
      pathCount: 0,
      gradients: 0,
      palette: null,
      hasTransparency: true,
      name: 'Sign Guy logo example',
    };
    state.artwork = artwork;
    state.removeBg = artwork.hasTransparency ? false : true;
    els.removeBg.checked = state.removeBg;
    state.fixFloatingRegions = false;
    state.floatingSupportColour = DEFAULT_FLOATING_SUPPORT_COLOUR;
    state.targetColorCount = 8;
    state.colorOverrides = [];
    state.frontColoursCustomized = false;
    state.selectedColor = 0;
    state.selectedColourTarget = { type: 'front', index: 0 };
    state.previewZoom = 1;
    state.previewPan = { x: 0, y: 0 };
    state.dismissedPreviewAlert = '';
    resetRotation();
    state.rotation = { x: 0, y: -18, z: 0 };
    initEditState(artwork);
    state.processed = processArtwork(artwork);
    if (state.processed.naturalColourCount) state.targetColorCount = state.processed.naturalColourCount;
    syncColorOverrides();
    renderPreview();
    renderDiagnostics();
    if (els.submitDesign) els.submitDesign.disabled = true;
    updateProjectControls();
    setStatus('Ready');
  } catch (error) {
    console.error(error);
    state.isDefaultPreview = true;
    state.fileName = '';
    renderUploadControl();
    renderPreviewTitle();
    renderEmptyPreview();
  } finally {
  }
}

async function loadDefaultHypeChainProject() {
  state.hypeDefaultProjectLoading = true;
  try {
    if (window.SIGN_GUY_DEFAULT_HYPE_CHAIN_PROJECT) {
      validateSignGuyProject(window.SIGN_GUY_DEFAULT_HYPE_CHAIN_PROJECT);
      restoreHypeChainProject(window.SIGN_GUY_DEFAULT_HYPE_CHAIN_PROJECT, { isExampleProject: true });
      setStatus('Ready');
      return;
    }
    const response = await fetch(DEFAULT_HYPE_CHAIN_PROJECT_SRC, { cache: 'no-store' });
    if (!response.ok) throw new Error(`Default Hype Chain project returned ${response.status}`);
    const project = await response.json();
    validateSignGuyProject(project);
    restoreHypeChainProject(project, { isExampleProject: true });
    setStatus('Ready');
  } catch (error) {
    console.error('Could not load default Hype Chain project', error);
  } finally {
    state.hypeDefaultProjectLoading = false;
  }
}

function initEditState(artwork = state.artwork) {
  state.edit = {
    crop: state.isDefaultPreview ? { x: 0, y: 0, w: 1, h: 1 } : detectDefaultCrop(artwork),
    cropAspect: 'free',
    zoom: 0.86,
  };
}

function detectDefaultCrop(artwork) {
  return getFullImageDefaultCrop(artwork);
}

function getFullImageDefaultCrop(artwork) {
  return normalizeCrop({
    x: -DEFAULT_CROP_OUTER_MARGIN,
    y: -DEFAULT_CROP_OUTER_MARGIN,
    w: 1 + DEFAULT_CROP_OUTER_MARGIN * 2,
    h: 1 + DEFAULT_CROP_OUTER_MARGIN * 2,
  });
}

function getTransparentArtworkContentBounds(data, width, height) {
  const alphaBounds = getImageDataAlphaBounds(data, width, height, 1);
  if (!alphaBounds) return null;
  const backgrounds = collectTransparentInteriorBackgroundSeeds(data, width, height, alphaBounds);
  if (!backgrounds.length) return alphaBounds;
  let minX = width;
  let minY = height;
  let maxX = -1;
  let maxY = -1;
  const threshold = 44;
  for (let y = alphaBounds.y; y < alphaBounds.y + alphaBounds.h; y += 1) {
    for (let x = alphaBounds.x; x < alphaBounds.x + alphaBounds.w; x += 1) {
      const offset = (y * width + x) * 4;
      if (data[offset + 3] < 34) continue;
      const rgb = [data[offset], data[offset + 1], data[offset + 2]];
      if (backgrounds.some((seed) => colourDistance(rgb, seed) <= threshold)) continue;
      minX = Math.min(minX, x);
      minY = Math.min(minY, y);
      maxX = Math.max(maxX, x);
      maxY = Math.max(maxY, y);
    }
  }
  if (maxX < minX) return alphaBounds;
  return { x: minX, y: minY, w: maxX - minX + 1, h: maxY - minY + 1 };
}

function collectTransparentInteriorBackgroundSeeds(data, width, height, bounds) {
  const samples = [];
  const edge = Math.max(2, Math.round(Math.min(bounds.w, bounds.h) * 0.035));
  const zones = [
    [bounds.x, bounds.y, bounds.x + bounds.w, bounds.y + edge],
    [bounds.x, bounds.y + bounds.h - edge, bounds.x + bounds.w, bounds.y + bounds.h],
    [bounds.x, bounds.y, bounds.x + edge, bounds.y + bounds.h],
    [bounds.x + bounds.w - edge, bounds.y, bounds.x + bounds.w, bounds.y + bounds.h],
  ];
  zones.forEach(([x0, y0, x1, y1]) => {
    for (let y = Math.max(0, y0); y < Math.min(height, y1); y += 1) {
      for (let x = Math.max(0, x0); x < Math.min(width, x1); x += 1) {
        const offset = (y * width + x) * 4;
        if (data[offset + 3] < 180) continue;
        const rgb = [data[offset], data[offset + 1], data[offset + 2]];
        if (colourLuma(rgb) < 190 || colourChroma(rgb) > 36) continue;
        samples.push(rgb);
      }
    }
  });
  if (!samples.length) return [];
  const avg = samples.reduce((sum, rgb) => {
    sum[0] += rgb[0];
    sum[1] += rgb[1];
    sum[2] += rgb[2];
    return sum;
  }, [0, 0, 0]).map((value) => value / samples.length);
  return [avg];
}

function cropFromBounds(bounds, width, height, padRatio = 0.04) {
  if (!bounds) return { x: 0, y: 0, w: 1, h: 1 };
  if (typeof padRatio === 'object' && Number(padRatio.scale) > 1) {
    const scale = Number(padRatio.scale);
    const centerX = bounds.x + bounds.w / 2;
    const centerY = bounds.y + bounds.h / 2;
    const minPixelPad = Math.max(12, Math.round(Math.max(width, height) * 0.035));
    const desiredW = Math.min(width, bounds.w * scale + minPixelPad * 2);
    const desiredH = Math.min(height, bounds.h * scale + minPixelPad * 2);
    const minX = clamp(centerX - desiredW / 2, 0, Math.max(0, width - desiredW));
    const minY = clamp(centerY - desiredH / 2, 0, Math.max(0, height - desiredH));
    return {
      x: minX / width,
      y: minY / height,
      w: Math.max(0.08, desiredW / width),
      h: Math.max(0.08, desiredH / height),
    };
  }
  const pad = typeof padRatio === 'number'
    ? { x: padRatio, top: padRatio, bottom: padRatio }
    : {
      x: Number(padRatio.x ?? padRatio.side ?? 0.04),
      top: Number(padRatio.top ?? padRatio.y ?? 0.04),
      bottom: Number(padRatio.bottom ?? padRatio.y ?? padRatio.top ?? 0.04),
    };
  const padX = width * pad.x;
  const padTop = height * pad.top;
  const padBottom = height * pad.bottom;
  const minX = clamp(bounds.x - padX, 0, width);
  const minY = clamp(bounds.y - padTop, 0, height);
  const maxX = clamp(bounds.x + bounds.w + padX, 0, width);
  const maxY = clamp(bounds.y + bounds.h + padBottom, 0, height);
  const desiredHeight = Math.min(height, (bounds.h + padTop + padBottom));
  const adjustedMinY = maxY >= height - 1
    ? Math.max(0, height - desiredHeight)
    : minY;
  const crop = {
    x: minX / width,
    y: adjustedMinY / height,
    w: Math.max(0.08, (maxX - minX) / width),
    h: Math.max(0.08, (maxY - adjustedMinY) / height),
  };
  if (crop.x <= 0.035 && crop.x + crop.w >= 0.965) {
    crop.x = 0;
    crop.w = 1;
  }
  if (crop.y <= 0.035 && crop.y + crop.h >= 0.965) {
    crop.y = 0;
    crop.h = 1;
  }
  return crop;
}

function openWizard(step) {
  state.wizardStep = step;
  document.body.classList.add('wizard-open');
  updateViewportUnits();
  els.wizard.classList.remove('hidden');
  els.wizard.setAttribute('aria-hidden', 'false');
  renderWizardStep();
}

function closeWizard() {
  state.wizardStep = null;
  closeColourPopover();
  document.body.classList.remove('wizard-open');
  els.wizard.classList.add('hidden');
  els.wizard.setAttribute('aria-hidden', 'true');
}

function renderWizardStep() {
  if (!state.wizardStep || !state.artwork) return;
  closeColourPopover();
  if (state.wizardStep === 'edit') renderEditStep();
  if (state.wizardStep === 'vector') renderVectorStep();
  if (state.wizardStep === 'mapping') renderMappingStep();
  if (state.wizardStep === 'details') renderDetailsStep();
}

function renderEditStep() {
  els.wizardTitle.textContent = 'Edit Your Image';
  if (isMobilePreviewViewport()) state.edit.cropAspect = 'free';
  els.wizardImage.onload = () => updateCropBox();
  els.wizardImage.src = renderEditArtworkPreviewUrl(state.artwork);
  els.wizardImage.style.setProperty('--wizard-zoom', state.edit.zoom);
  els.cropBox.classList.add('visible');
  els.cropBox.classList.toggle('circle', state.edit.cropAspect === 'circle');
  els.previewTools.classList.remove('hidden');
  els.wizardSide.innerHTML = `
    <h3 class="crop-settings-title">Crop</h3>
    <div class="crop-presets">
      ${CROP_PRESETS.map((preset) => `
        <button class="crop-preset ${state.edit.cropAspect === preset.id ? 'active' : ''}" type="button" data-crop-preset="${preset.id}">
          <span class="crop-icon ${preset.icon}"></span>
          <span>${preset.label}</span>
        </button>
      `).join('')}
    </div>
    <label class="switch-row">
      <span>Remove Background</span>
      <input id="wizardRemoveBg" type="checkbox" ${state.removeBg ? 'checked' : ''} />
    </label>
    <p class="wizard-helper-text">Enable if your image does not already have a transparent checkerboard background.</p>
    <label class="switch-row">
      <span>Fix floating regions</span>
      <input id="wizardFixFloatingRegions" type="checkbox" ${state.fixFloatingRegions ? 'checked' : ''} />
    </label>
    <p class="wizard-helper-text">Enable if your logo has floating pieces disconnected from the main shape.</p>
  `;
  els.wizardFooter.innerHTML = `
    <button class="secondary-button" type="button" data-wizard-action="cancel">Cancel</button>
    <button class="primary-button" type="button" data-wizard-action="to-vector">Next</button>
  `;
  bindWizardButtons();
  requestAnimationFrame(centerWizardPreview);
  requestAnimationFrame(updateCropBox);
}

function renderEditArtworkPreviewUrl(artwork) {
  if (!artwork || (!state.removeBg && !state.fixFloatingRegions)) return artwork?.dataUrl || '';
  const crop = { x: 0, y: 0, w: 1, h: 1 };
  return renderEditedArtworkCanvas(artwork, crop, 900).toDataURL('image/png');
}

function renderEditedArtworkCanvas(artwork, crop, maxSide) {
  const srcW = Math.max(1, Math.round(artwork.image.naturalWidth * crop.w));
  const srcH = Math.max(1, Math.round(artwork.image.naturalHeight * crop.h));
  const scale = maxSide / Math.max(srcW, srcH);
  const width = Math.max(12, Math.round(srcW * scale));
  const height = Math.max(12, Math.round(srcH * scale));
  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  ctx.clearRect(0, 0, width, height);
  drawArtworkIntoExpandedCrop(ctx, artwork, crop, scale);
  if (state.removeBg) {
    const img = ctx.getImageData(0, 0, width, height);
    removeConnectedBackgroundFromImageData(img.data, width, height);
    ctx.putImageData(img, 0, 0);
  }
  if (state.fixFloatingRegions) {
    connectFloatingRegionsOnCanvas(canvas, ctx, hexToRgb(state.floatingSupportColour || DEFAULT_FLOATING_SUPPORT_COLOUR));
  }
  return canvas;
}

function drawArtworkIntoExpandedCrop(ctx, artwork, crop, scale) {
  const imageWidth = artwork.image.naturalWidth || artwork.image.width;
  const imageHeight = artwork.image.naturalHeight || artwork.image.height;
  const srcX = imageWidth * crop.x;
  const srcY = imageHeight * crop.y;
  const srcW = imageWidth * crop.w;
  const srcH = imageHeight * crop.h;
  const visibleX = clamp(srcX, 0, imageWidth);
  const visibleY = clamp(srcY, 0, imageHeight);
  const visibleRight = clamp(srcX + srcW, 0, imageWidth);
  const visibleBottom = clamp(srcY + srcH, 0, imageHeight);
  const visibleW = Math.max(0, visibleRight - visibleX);
  const visibleH = Math.max(0, visibleBottom - visibleY);
  if (!visibleW || !visibleH) return;
  ctx.drawImage(
    artwork.image,
    visibleX,
    visibleY,
    visibleW,
    visibleH,
    (visibleX - srcX) * scale,
    (visibleY - srcY) * scale,
    visibleW * scale,
    visibleH * scale,
  );
}

function renderVectorStep() {
  els.wizardTitle.textContent = 'Vectorized Result';
  setWizardPreview(renderMappedArtworkUrl(state.processed) || state.processed?.artworkUrl || state.artwork.dataUrl);
  els.wizardSide.innerHTML = `
    <h3>Vectorized result</h3>
    <p>The artwork has been flattened into printable colour regions and a custom outer silhouette. If this does not look right, try again or go back to crop/background cleanup.</p>
    <div class="detail-list vector-summary-list">
      <div class="detail-row"><span class="map-number">${state.processed?.colours.length || 0}</span><span>detected colours</span><strong>max 8</strong></div>
      <div class="detail-row"><span class="map-number">${state.tolerance}</span><span>merge tolerance</span><strong>auto</strong></div>
    </div>
    ${renderMappingControlsMarkup()}
  `;
  els.wizardFooter.innerHTML = `
    <button class="secondary-button" type="button" data-wizard-action="to-edit">Back</button>
    <button class="secondary-button" type="button" data-wizard-action="try-vector">Try Again</button>
    <button class="primary-button" type="button" data-wizard-action="to-details">Next</button>
  `;
  bindWizardButtons();
  bindMappingControls();
}

function renderMappingStep() {
  els.wizardTitle.textContent = 'Auto Color Mapping';
  setWizardPreview(renderMappedArtworkUrl(state.processed) || state.processed?.artworkUrl || state.artwork.dataUrl);
  els.wizardSide.innerHTML = renderMappingControlsMarkup();
  els.wizardFooter.innerHTML = `
    <button class="secondary-button" type="button" data-wizard-action="to-vector">Back</button>
    <button class="primary-button" type="button" data-wizard-action="to-details">Next</button>
  `;
  bindWizardButtons();
  bindMappingControls();
}

function renderMappingControlsMarkup() {
  const colours = state.processed?.colours || [];
  return `
    <h3 class="mapping-controls-title">Color Count</h3>
    <p>Adjust the number of colours to match your filaments. You can edit colours manually in the next step.</p>
    <div class="colour-count-row">
      <input id="mapColorCount" type="range" min="1" max="8" value="${state.targetColorCount}" />
      <span class="count-badge">${state.targetColorCount}</span>
    </div>
    <h3>Mapping</h3>
    <div class="mapping-list">
      ${colours.map((region, idx) => {
        const hex = getDisplayColour(idx, region.hex);
        const label = region.isFloatingSupport ? 'S' : `${idx + 1}`;
        return `
          <div class="mapping-row">
            <span class="map-dot" style="background:${region.hex}"></span>
            <span class="map-arrow">&rarr;</span>
            <span class="map-number" style="${colourTokenStyle(region.hex)}">${label}</span>
            <span class="colour-dot" style="background:${hex}"></span>
          </div>
        `;
      }).join('')}
    </div>
  `;
}

function bindMappingControls() {
  const colorCount = document.querySelector('#mapColorCount');
  if (!colorCount) return;
  const colorCountBadge = els.wizardSide.querySelector('.count-badge');
  colorCount.addEventListener('input', () => {
    state.targetColorCount = Number(colorCount.value);
    if (colorCountBadge) colorCountBadge.textContent = String(state.targetColorCount);
  });
  colorCount.addEventListener('change', async () => {
    state.targetColorCount = Number(colorCount.value);
    state.colorOverrides = [];
    state.frontColoursCustomized = true;
    await reprocess();
  });
}

function renderDetailsStep() {
  els.wizardTitle.textContent = 'Edit Color Details';
  setWizardPreview(renderMappedArtworkUrl(state.processed) || state.processed?.artworkUrl || state.artwork.dataUrl);
  const colours = state.processed?.colours || [];
  els.wizardSide.innerHTML = `
    <div class="section-heading">
      <h3>Colors Being Used</h3>
    </div>
    <div class="colour-chips">
      ${colours.map((region, idx) => {
        const hex = getDisplayColour(idx, region.hex);
        const label = region.isFloatingSupport ? 'S' : `${idx + 1}`;
        return `<button class="colour-chip ${state.selectedColor === idx ? 'active' : ''}" type="button" data-select-colour="${idx}" style="${colourTokenStyle(hex)}">${label}</button>`;
      }).join('')}
      <button class="colour-chip colour-add-chip" type="button" data-wizard-action="add-colour" aria-label="Add colour">+</button>
    </div>
    <div class="section-heading">
      <h3>Mapping</h3>
      <button class="reset-button" type="button" data-wizard-action="reset-colours">Reset</button>
    </div>
    <div class="detail-list colour-detail-list">
      ${colours.map((region, idx) => {
        const hex = getDisplayColour(idx, region.hex);
        const label = region.isFloatingSupport ? 'Support' : `${idx + 1}`;
        return `
          <button class="detail-row colour-detail-row" type="button" data-edit-colour="${idx}" style="${colourTokenStyle(hex)}" aria-label="Edit ${region.isFloatingSupport ? 'floating support colour' : `colour ${idx + 1}`}">
            <span>${label}</span>
            <strong>${hex}</strong>
          </button>
        `;
      }).join('')}
    </div>
  `;
  els.wizardFooter.innerHTML = `
    <button class="secondary-button" type="button" data-wizard-action="to-vector">Back</button>
    <button class="primary-button" type="button" data-wizard-action="confirm">Confirm</button>
  `;
  bindWizardButtons();
}

function colourTokenStyle(hex) {
  const normalized = normalizeHex(hex);
  const ink = readableTextColour(normalized);
  return `--token-color:${normalized};--token-ink:${ink};color:${ink};`;
}

function readableTextColour(hex) {
  const [r, g, b] = hexToRgb(normalizeHex(hex));
  return ((r * 299 + g * 587 + b * 114) / 1000) > 150 ? '#111111' : '#ffffff';
}

function setWizardPreview(src) {
  els.wizardImage.onload = null;
  els.wizardImage.onload = () => {
    if (state.wizardStep !== 'edit') centerWizardPreview();
  };
  els.wizardImage.src = src;
  els.wizardImage.style.setProperty('--wizard-zoom', state.edit.zoom);
  els.cropBox.classList.remove('visible', 'circle');
  els.previewTools.classList.remove('hidden');
  requestAnimationFrame(centerWizardPreview);
}

function centerWizardPreview() {
  els.wizardImage.scrollIntoView({ block: 'center', inline: 'center' });
}

function bindWizardButtons() {
  els.wizardSide.querySelectorAll('[data-crop-preset]').forEach((button) => {
    button.addEventListener('click', () => setCropPreset(button.dataset.cropPreset));
  });
  els.wizardSide.querySelector('#wizardRemoveBg')?.addEventListener('change', async (event) => {
    state.removeBg = event.target.checked;
    els.removeBg.checked = state.removeBg;
    state.edit.crop = { x: 0, y: 0, w: 1, h: 1 };
    await reprocess();
    renderEditStep();
  });
  els.wizardSide.querySelector('#wizardFixFloatingRegions')?.addEventListener('change', async (event) => {
    state.fixFloatingRegions = event.target.checked;
    state.processingDirty = true;
    renderEditStep();
  });
  [...els.wizardFooter.querySelectorAll('[data-wizard-action]'), ...els.wizardSide.querySelectorAll('[data-wizard-action]')].forEach((button) => {
    button.addEventListener('click', () => handleWizardAction(button.dataset.wizardAction));
  });
  els.wizardSide.querySelectorAll('[data-select-colour]').forEach((button) => {
    button.addEventListener('click', () => {
      state.selectedColor = Number(button.dataset.selectColour);
      renderDetailsStep();
    });
  });
  els.wizardSide.querySelectorAll('[data-edit-colour]').forEach((button) => {
    button.addEventListener('click', () => openColourPopover(Number(button.dataset.editColour), button));
  });
  els.wizardSide.querySelectorAll('[data-edit-shell]').forEach((button) => {
    button.addEventListener('click', () => openShellColourPopover(button.dataset.editShell, button));
  });
}

async function handleWizardAction(action) {
  if (action === 'cancel') {
    if (state.uploadTarget === 'hype') restoreLedUploadState();
    closeWizard();
    return;
  }
  if (action === 'to-edit') {
    openWizard('edit');
    return;
  }
  if (action === 'to-vector') {
    try {
      if (!state.processed || state.processingDirty) await reprocess({ skipWizardRender: true });
      openWizard('vector');
    } catch (error) {
      console.error('Could not process artwork before vector step', error);
      setStatus('Processing failed');
      els.submitNote.textContent = error?.message ? `Processing failed: ${error.message}` : 'Processing failed. Please try again.';
    }
    return;
  }
  if (action === 'try-vector') {
    state.tolerance = clamp(state.tolerance + 8, 18, 90);
    await reprocess({ skipWizardRender: true });
    openWizard('vector');
    return;
  }
  if (action === 'to-mapping') {
    openWizard('mapping');
    return;
  }
  if (action === 'to-details') {
    openWizard('details');
    return;
  }
  if (action === 'reset-colours') {
    state.colorOverrides = [];
    state.floatingSupportColour = DEFAULT_FLOATING_SUPPORT_COLOUR;
    state.frontColoursCustomized = false;
    renderPreview();
    renderShellColourControls();
    renderDetailsStep();
    return;
  }
  if (action === 'add-colour') {
    state.targetColorCount = clamp(state.targetColorCount + 1, 1, 8);
    state.frontColoursCustomized = true;
    await reprocess({ skipWizardRender: true });
    openWizard('details');
    return;
  }
  if (action === 'confirm') {
    if (state.uploadTarget === 'hype') {
      completeHypeLogoImport();
      closeWizard();
      return;
    }
    closeWizard();
  }
}

function completeHypeLogoImport() {
  const sourceName = state.fileName || 'hype-chain-logo.png';
  const pendantArtwork = createHypePendantArtworkFromProcessed(state.processed);
  const dataUrl = pendantArtwork?.dataUrl || renderMappedArtworkUrl(state.processed) || state.processed?.artworkUrl || state.artwork?.dataUrl || '';
  const pendantSourceColours = (state.processed?.colours || []).map((region, index) => getDisplayColour(index, region.hex));
  const pendantColourLabels = (state.processed?.colours || []).map((region, index) => (region.isFloatingSupport ? 'S' : String(index + 1)));
  const processedWidth = Number(pendantArtwork?.width || state.processed?.width || state.artwork?.image?.naturalWidth || state.artwork?.image?.width);
  const processedHeight = Number(pendantArtwork?.height || state.processed?.height || state.artwork?.image?.naturalHeight || state.artwork?.image?.height);
  state.hype.logoFileName = sourceName;
  state.hype.logoDataUrl = dataUrl;
  state.hype.isExampleProject = false;
  state.hype.pendantBaseDataUrl = dataUrl;
  state.hype.logoAspect = processedWidth > 0 && processedHeight > 0 ? clamp(processedWidth / processedHeight, 0.35, 2.4) : 1;
  state.hype.pendantSourceColours = pendantSourceColours.map((hex) => normalizeHex(hex));
  state.hype.pendantColours = state.hype.pendantSourceColours.map((hex) => normalizeHex(hex));
  state.hype.pendantColourLabels = pendantColourLabels;
  state.hype.pendantRegionShapes = buildHypePendantRegionShapes(state.processed, pendantArtwork?.bounds);
  state.hype.pendantCasing = normalizeHex(state.hype.pendantCasing || state.hype.pendant || '#202326');
  applyHypePendantColoursToChain();
  restoreLedUploadState();
  applyHypeStateToControls();
  selectProductType('hype');
  scheduleHypeRender(40);
  updateProjectControls();
  setStatus('Hype logo ready');
}

function createHypePendantArtworkFromProcessed(processed) {
  if (!processed?.artworkCanvas) return null;
  const source = state.frontColoursCustomized ? createMappedArtworkCanvas(processed) : processed.artworkCanvas;
  const trimmed = trimCanvasToVisibleAlpha(source, 20);
  return {
    canvas: trimmed.canvas,
    dataUrl: trimmed.canvas.toDataURL('image/png'),
    width: trimmed.canvas.width,
    height: trimmed.canvas.height,
    bounds: trimmed.bounds,
  };
}

function trimCanvasToVisibleAlpha(source, alphaThreshold = 1) {
  const ctx = source.getContext('2d', { willReadFrequently: true });
  const frame = ctx.getImageData(0, 0, source.width, source.height);
  const bounds = getImageDataAlphaBounds(frame.data, source.width, source.height, alphaThreshold);
  if (!bounds) {
    return {
      canvas: source,
      bounds: { x: 0, y: 0, w: source.width, h: source.height },
    };
  }
  const canvas = document.createElement('canvas');
  canvas.width = Math.max(1, bounds.w);
  canvas.height = Math.max(1, bounds.h);
  const nextCtx = canvas.getContext('2d', { willReadFrequently: true });
  nextCtx.clearRect(0, 0, canvas.width, canvas.height);
  nextCtx.drawImage(source, bounds.x, bounds.y, bounds.w, bounds.h, 0, 0, bounds.w, bounds.h);
  return { canvas, bounds };
}

function buildHypePendantRegionShapes(processed, bounds) {
  if (!processed?.colours?.length || !bounds) return [];
  const width = processed.width;
  const height = processed.height;
  const trim = {
    x: clamp(Math.round(bounds.x), 0, width - 1),
    y: clamp(Math.round(bounds.y), 0, height - 1),
    w: clamp(Math.round(bounds.w), 1, width),
    h: clamp(Math.round(bounds.h), 1, height),
  };
  const totalVisible = Math.max(1, trim.w * trim.h);
  const minComponentPixels = Math.max(10, Math.round(totalVisible * 0.00022));
  return processed.colours.map((region, regionIndex) => {
    const mask = new Uint8Array(trim.w * trim.h);
    for (let y = 0; y < trim.h; y += 1) {
      for (let x = 0; x < trim.w; x += 1) {
        const sourceIndex = (trim.y + y) * width + trim.x + x;
        if (processed.alphaMask?.[sourceIndex] && processed.regionIndex?.[sourceIndex] === regionIndex) {
          mask[y * trim.w + x] = 1;
        }
      }
    }
    const components = getBinaryMaskComponents(mask, trim.w, trim.h, minComponentPixels)
      .slice(0, 42)
      .map((component) => {
        const componentMask = new Uint8Array(mask.length);
        component.pixels.forEach((index) => {
          componentMask[index] = 1;
        });
        const outline = traceMaskOutline(componentMask, trim.w, trim.h);
        if (outline.length < 8) return null;
        const smoothed = smoothPolygon(outline, 1);
        const simplified = simplifyPolygon(smoothed, Math.max(0.85, Math.max(trim.w, trim.h) / 700));
        return simplified.slice(0, 140).map(([x, y]) => [
          clamp(x / trim.w, 0, 1),
          clamp(y / trim.h, 0, 1),
        ]);
      })
      .filter(Boolean);
    return {
      colourIndex: regionIndex,
      hex: normalizeHex(region.hex),
      components,
    };
  }).filter((region) => region.components.length);
}

function getBinaryMaskComponents(mask, width, height, minPixels = 1) {
  const seen = new Uint8Array(mask.length);
  const components = [];
  const stack = [];
  for (let i = 0; i < mask.length; i += 1) {
    if (!mask[i] || seen[i]) continue;
    const pixels = [];
    seen[i] = 1;
    stack.push(i);
    while (stack.length) {
      const current = stack.pop();
      pixels.push(current);
      const x = current % width;
      const y = Math.floor(current / width);
      [
        [x + 1, y],
        [x - 1, y],
        [x, y + 1],
        [x, y - 1],
      ].forEach(([nx, ny]) => {
        if (nx < 0 || ny < 0 || nx >= width || ny >= height) return;
        const next = ny * width + nx;
        if (!mask[next] || seen[next]) return;
        seen[next] = 1;
        stack.push(next);
      });
    }
    if (pixels.length >= minPixels) components.push({ pixels });
  }
  return components.sort((a, b) => b.pixels.length - a.pixels.length);
}

async function rebuildHypePendantLogoDataUrl() {
  const baseUrl = state.hype.pendantBaseDataUrl || state.hype.logoDataUrl;
  const sourceColours = state.hype.pendantSourceColours || [];
  const targetColours = getHypePendantColours();
  if (!baseUrl || !sourceColours.length || !targetColours.length) {
    scheduleHypeRender(0);
    return;
  }
  const image = await loadImage(baseUrl);
  const canvas = document.createElement('canvas');
  canvas.width = image.naturalWidth || image.width;
  canvas.height = image.naturalHeight || image.height;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.drawImage(image, 0, 0, canvas.width, canvas.height);
  const frame = ctx.getImageData(0, 0, canvas.width, canvas.height);
  const sourceRgb = sourceColours.map((hex) => hexToRgb(hex));
  const targetRgb = targetColours.map((hex) => hexToRgb(hex));
  for (let i = 0; i < frame.data.length; i += 4) {
    if (frame.data[i + 3] < 8) continue;
    let bestIndex = 0;
    let bestDistance = Infinity;
    for (let colourIndex = 0; colourIndex < sourceRgb.length; colourIndex += 1) {
      const distance = colourDistance(
        [frame.data[i], frame.data[i + 1], frame.data[i + 2]],
        sourceRgb[colourIndex],
      );
      if (distance < bestDistance) {
        bestDistance = distance;
        bestIndex = colourIndex;
      }
    }
    const rgb = targetRgb[bestIndex] || targetRgb[0];
    frame.data[i] = rgb[0];
    frame.data[i + 1] = rgb[1];
    frame.data[i + 2] = rgb[2];
  }
  ctx.putImageData(frame, 0, 0);
  state.hype.logoDataUrl = canvas.toDataURL('image/png');
  scheduleHypeRender(0);
}

function setCropPreset(id) {
  const preset = CROP_PRESETS.find((item) => item.id === id);
  if (!preset) return;
  state.edit.cropAspect = id;
  state.processingDirty = true;
  if (preset.ratio) {
    const imageRatio = state.artwork.image.naturalWidth / state.artwork.image.naturalHeight;
    let w = 1;
    let h = 1;
    if (imageRatio > preset.ratio) {
      w = preset.ratio / imageRatio;
    } else {
      h = imageRatio / preset.ratio;
    }
    state.edit.crop = { x: (1 - w) / 2, y: (1 - h) / 2, w, h };
  }
  renderEditStep();
}

function setupCropInteraction() {
  let drag = null;
  els.cropBox.addEventListener('pointerdown', (event) => {
    if (state.wizardStep !== 'edit') return;
    event.preventDefault();
    const rect = getDisplayedImageRect();
    const handle = event.target.closest('.crop-handle')?.dataset.handle || 'move';
    drag = {
      handle,
      pointerId: event.pointerId,
      startX: event.clientX,
      startY: event.clientY,
      crop: { ...state.edit.crop },
      rect,
    };
    els.cropBox.setPointerCapture(event.pointerId);
  });
  const updateDrag = (event) => {
    if (!drag) return;
    const dx = (event.clientX - drag.startX) / drag.rect.width;
    const dy = (event.clientY - drag.startY) / drag.rect.height;
    let crop = { ...drag.crop };
    if (drag.handle === 'move') {
      crop.x += dx;
      crop.y += dy;
    } else {
      const min = 0.06;
      let left = drag.crop.x;
      let right = drag.crop.x + drag.crop.w;
      let top = drag.crop.y;
      let bottom = drag.crop.y + drag.crop.h;
      const minEdge = -CROP_EXTEND_LIMIT;
      const maxEdge = 1 + CROP_EXTEND_LIMIT;
      if (drag.handle.includes('e')) right = clamp(right + dx, left + min, maxEdge);
      if (drag.handle.includes('s')) bottom = clamp(bottom + dy, top + min, maxEdge);
      if (drag.handle.includes('w')) left = clamp(left + dx, minEdge, right - min);
      if (drag.handle.includes('n')) top = clamp(top + dy, minEdge, bottom - min);
      crop = { x: left, y: top, w: right - left, h: bottom - top };
      crop = enforceCropAspect(crop, drag.handle);
    }
    state.edit.crop = normalizeCrop(crop);
    state.processingDirty = true;
    updateCropBox();
  };
  const stopDrag = () => {
    drag = null;
  };
  window.addEventListener('pointermove', updateDrag);
  window.addEventListener('pointerup', stopDrag);
  window.addEventListener('pointercancel', stopDrag);
  els.cropBox.addEventListener('lostpointercapture', stopDrag);
  window.addEventListener('resize', updateCropBox);
}

function enforceCropAspect(crop, handle) {
  const preset = CROP_PRESETS.find((item) => item.id === state.edit.cropAspect);
  if (!preset?.ratio) return crop;
  const naturalRatio = state.artwork.image.naturalWidth / state.artwork.image.naturalHeight;
  const targetH = (crop.w * naturalRatio) / preset.ratio;
  if (handle.includes('n')) crop.y += crop.h - targetH;
  crop.h = targetH;
  return crop;
}

function normalizeCrop(crop) {
  const min = 0.06;
  const max = 1 + CROP_EXTEND_LIMIT * 2;
  crop.w = clamp(crop.w, min, max);
  crop.h = clamp(crop.h, min, max);
  crop.x = clamp(crop.x, -CROP_EXTEND_LIMIT, 1 + CROP_EXTEND_LIMIT - crop.w);
  crop.y = clamp(crop.y, -CROP_EXTEND_LIMIT, 1 + CROP_EXTEND_LIMIT - crop.h);
  return crop;
}

function getDisplayedImageRect() {
  const imageRect = els.wizardImage.getBoundingClientRect();
  const boardRect = els.wizardArtboard.getBoundingClientRect();
  return {
    left: imageRect.left - boardRect.left,
    top: imageRect.top - boardRect.top,
    width: imageRect.width,
    height: imageRect.height,
  };
}

function updateCropBox() {
  if (state.wizardStep !== 'edit' || !state.artwork) return;
  const rect = getDisplayedImageRect();
  const crop = state.edit.crop;
  els.cropBox.style.left = `${rect.left + crop.x * rect.width}px`;
  els.cropBox.style.top = `${rect.top + crop.y * rect.height}px`;
  els.cropBox.style.width = `${crop.w * rect.width}px`;
  els.cropBox.style.height = `${crop.h * rect.height}px`;
}

function setWizardZoom(value) {
  state.edit.zoom = clamp(value, 0.7, 1.8);
  els.wizardImage.style.setProperty('--wizard-zoom', state.edit.zoom);
  requestAnimationFrame(updateCropBox);
}

function syncColorOverrides(previousColourSnapshot = null) {
  if (!state.processed) return;
  const previousNormalColours = Array.isArray(previousColourSnapshot)
    ? previousColourSnapshot.filter((item) => !item.isFloatingSupport)
    : null;
  const usedPrevious = new Set();
  state.colorOverrides = state.processed.colours.map((region, idx) => {
    if (region.isFloatingSupport) {
      const support = normalizeHex(state.floatingSupportColour || region.hex || DEFAULT_FLOATING_SUPPORT_COLOUR);
      state.floatingSupportColour = support;
      return support;
    }

    const sourceHex = normalizeHex(region.hex);
    if (previousNormalColours?.length) {
      let bestIndex = -1;
      let bestDistance = Infinity;
      previousNormalColours.forEach((item, previousIdx) => {
        if (usedPrevious.has(previousIdx)) return;
        const distance = colourDistance(hexToRgb(sourceHex), hexToRgb(item.hex));
        if (distance < bestDistance) {
          bestDistance = distance;
          bestIndex = previousIdx;
        }
      });
      if (bestIndex >= 0 && bestDistance <= 30) {
        usedPrevious.add(bestIndex);
        return normalizeHex(previousNormalColours[bestIndex].display || sourceHex);
      }
      return sourceHex;
    }

    return normalizeHex(state.colorOverrides[idx] || sourceHex);
  });
  state.selectedColor = clamp(state.selectedColor, 0, Math.max(0, state.processed.colours.length - 1));
}

function getDisplayColour(index, fallback) {
  return normalizeHex(state.colorOverrides[index] || fallback || '#ffffff');
}

function renderMappedArtworkUrl(processed) {
  if (!processed?.colours.length) return processed?.artworkUrl || '';
  if (!state.frontColoursCustomized) return processed.artworkUrl || '';
  const canvas = document.createElement('canvas');
  canvas.width = processed.width;
  canvas.height = processed.height;
  const ctx = canvas.getContext('2d');
  const img = ctx.createImageData(processed.width, processed.height);
  const displayColours = processed.colours.map((region, idx) => hexToRgb(getDisplayColour(idx, region.hex)));
  for (let i = 0; i < processed.regionIndex.length; i += 1) {
    const region = processed.regionIndex[i];
    const o = i * 4;
    if (!processed.alphaMask[i] || region < 0 || !displayColours[region]) {
      img.data[o + 3] = 0;
      continue;
    }
    const rgb = displayColours[region];
    img.data[o] = rgb[0];
    img.data[o + 1] = rgb[1];
    img.data[o + 2] = rgb[2];
    img.data[o + 3] = processed.alphaValues?.[i] || 255;
  }
  ctx.putImageData(img, 0, 0);
  return canvas.toDataURL('image/png');
}

function buildPresetGrid() {
  els.presetGrid.innerHTML = PRESET_COLOURS.map((hex) => `<button type="button" data-preset-colour="${hex}" style="background:${hex}" aria-label="${hex}"></button>`).join('');
  els.presetGrid.querySelectorAll('[data-preset-colour]').forEach((button) => {
    button.addEventListener('click', () => applySelectedColour(button.dataset.presetColour));
  });
}

function openColourPopover(index, anchor) {
  openFrontColourPopover(index, anchor);
}

function openFrontColourPopover(index, anchor) {
  state.selectedColourTarget = { type: 'front', index };
  state.selectedColor = index;
  const hex = getDisplayColour(index, state.processed?.colours[index]?.hex);
  updatePopoverInputs(hex);
  const rect = anchor.getBoundingClientRect();
  els.colourPopover.style.left = `${Math.min(window.innerWidth - 275, rect.left + 8)}px`;
  els.colourPopover.style.top = `${Math.min(window.innerHeight - 360, rect.bottom + 8)}px`;
  els.colourPopover.classList.remove('hidden');
  renderUsedColourGrid();
  setPopoverTab('preset');
}

function openShellColourPopover(part, anchor) {
  state.selectedColourTarget = { type: 'shell', part };
  const hex = normalizeHex(state.shellColours[part]);
  updatePopoverInputs(hex);
  const rect = anchor.getBoundingClientRect();
  els.colourPopover.style.left = `${Math.min(window.innerWidth - 275, rect.left + 8)}px`;
  els.colourPopover.style.top = `${Math.min(window.innerHeight - 360, rect.bottom + 8)}px`;
  els.colourPopover.classList.remove('hidden');
  renderUsedColourGrid();
  setPopoverTab('preset');
}

function openHypeColourPopover(part, anchor) {
  state.selectedColourTarget = { type: 'hype', part };
  const hex = normalizeHex(state.hype[part] || '#ffffff');
  updatePopoverInputs(hex);
  const rect = anchor.getBoundingClientRect();
  els.colourPopover.style.left = `${Math.min(window.innerWidth - 275, rect.left + 8)}px`;
  els.colourPopover.style.top = `${Math.min(window.innerHeight - 360, rect.bottom + 8)}px`;
  els.colourPopover.classList.remove('hidden');
  renderUsedColourGrid();
  setPopoverTab('preset');
}

function openHypePendantColourPopover(index, anchor) {
  const colours = getHypePendantColours();
  state.selectedColourTarget = { type: 'hypePendant', index };
  const hex = normalizeHex(colours[index] || '#ffffff');
  updatePopoverInputs(hex);
  const rect = anchor.getBoundingClientRect();
  els.colourPopover.style.left = `${Math.min(window.innerWidth - 275, rect.left + 8)}px`;
  els.colourPopover.style.top = `${Math.min(window.innerHeight - 360, rect.bottom + 8)}px`;
  els.colourPopover.classList.remove('hidden');
  renderUsedColourGrid();
  setPopoverTab('used');
}

function closeColourPopover() {
  els.colourPopover.classList.add('hidden');
}

function setPopoverTab(tab) {
  if (tab === 'used') renderUsedColourGrid();
  document.querySelectorAll('[data-popover-tab]').forEach((button) => {
    button.classList.toggle('active', button.dataset.popoverTab === tab);
  });
  els.presetPane.classList.toggle('hidden', tab !== 'preset');
  els.usedPane?.classList.toggle('hidden', tab !== 'used');
  els.customPane.classList.toggle('hidden', tab !== 'custom');
}

function renderUsedColourGrid() {
  if (!els.usedGrid) return;
  const label = els.usedPane?.querySelector('p');
  if (state.productType === 'hype') {
    if (label) label.textContent = 'Used colours';
    const chainColours = uniqueHexColours(getHypePatternColours());
    const pendantColours = uniqueHexColours(collectHypePendantUsedColours());
    const markup = [
      renderUsedColourGroup('Hype Chain', chainColours),
      renderUsedColourGroup('Pendant', pendantColours),
    ].filter(Boolean).join('');
    els.usedGrid.innerHTML = markup || '<span class="used-empty">Choose Hype Chain colours first.</span>';
    bindUsedColourButtons();
    return;
  }
  if (label) label.textContent = 'Front';
  const colours = (state.processed?.colours || []).map((region, idx) => getDisplayColour(idx, region.hex));
  renderUsedColourButtons(colours, 'Upload a logo first.');
}

function renderUsedColourButtons(colours, emptyText) {
  const unique = uniqueHexColours(colours);
  els.usedGrid.innerHTML = unique.length
    ? unique.map((hex) => renderUsedColourButton(hex)).join('')
    : `<span class="used-empty">${emptyText}</span>`;
  bindUsedColourButtons();
}

function renderUsedColourGroup(label, colours) {
  const unique = uniqueHexColours(colours);
  if (!unique.length) return '';
  return `
    <span class="used-group-label">${label}</span>
    ${unique.map((hex) => renderUsedColourButton(hex)).join('')}
  `;
}

function renderUsedColourButton(hex) {
  return `<button type="button" data-used-colour="${hex}" style="background:${hex}" aria-label="${hex}"></button>`;
}

function bindUsedColourButtons() {
  els.usedGrid.querySelectorAll('[data-used-colour]').forEach((button) => {
    button.addEventListener('click', () => applySelectedColour(button.dataset.usedColour));
  });
}

function uniqueHexColours(colours) {
  return [...new Set((colours || []).map((hex) => normalizeUsedColour(hex)).filter(Boolean))];
}

function collectHypePendantUsedColours() {
  const colours = [];
  const add = (value) => {
    const normalized = normalizeUsedColour(value);
    if (normalized && !colours.includes(normalized)) colours.push(normalized);
  };
  add(state.hype.pendantCasing);
  add(state.hype.pendant);
  (state.hype.pendantColours || []).forEach(add);
  (state.hype.pendantSourceColours || []).forEach(add);
  getHypePendantColours().forEach(add);
  els.hypePendantColourRow?.querySelectorAll('[data-hype-pendant-casing], [data-hype-pendant-colour]').forEach((button) => {
    add(button.getAttribute('aria-label'));
    const dot = button.querySelector('i');
    add(dot?.dataset?.pendantColour);
    add(dot?.dataset?.pendantCasingColour);
    add(button.getAttribute('style'));
    add(dot?.getAttribute('style'));
    add(dot?.style.background || dot?.style.backgroundColor);
    add(dot ? window.getComputedStyle(dot).backgroundColor : '');
  });
  return colours;
}

function normalizeUsedColour(value) {
  const raw = String(value || '').trim();
  const hex = raw.match(/#[0-9a-f]{3,6}/i)?.[0];
  if (hex) return normalizeHex(hex);
  const rgbMatch = raw.match(/rgba?\(\s*([\d.]+)[,\s]+([\d.]+)[,\s]+([\d.]+)/i);
  if (rgbMatch) {
    return rgbToHex([
      Number(rgbMatch[1]),
      Number(rgbMatch[2]),
      Number(rgbMatch[3]),
    ]);
  }
  const normalized = normalizeHex(raw);
  if (normalized !== '#ffffff' || /^#(?:fff|ffffff)$/i.test(raw)) return normalized;
  const rgb = parseCssColour(raw);
  return rgb ? rgbToHex(rgb) : '';
}

window.SignGuyRenderUsedColourGrid = renderUsedColourGrid;

function updatePopoverInputs(hex) {
  const normalized = normalizeHex(hex);
  const rgb = hexToRgb(normalized);
  els.popoverSwatch.style.background = normalized;
  els.popoverHex.value = normalized;
  els.customColourInput.value = normalized;
  els.rgbR.value = rgb[0];
  els.rgbG.value = rgb[1];
  els.rgbB.value = rgb[2];
}

function applySelectedColour(hex) {
  const normalized = normalizeHex(hex);
  if (state.selectedColourTarget.type === 'shell') {
    state.shellColours[state.selectedColourTarget.part] = normalized;
    renderShellColourControls();
  } else if (state.selectedColourTarget.type === 'hypePendant') {
    const index = state.selectedColourTarget.index;
    const colours = getHypePendantColours();
    colours[index] = normalized;
    state.hype.pendantColours = colours;
    renderHypeColourControls();
    rebuildHypePendantLogoDataUrl().catch((error) => {
      console.error('Could not update Hype Chain pendant colours', error);
      scheduleHypeRender(0);
    });
  } else if (state.selectedColourTarget.type === 'hype') {
    state.hype[state.selectedColourTarget.part] = normalized;
    syncHypeDerivedColours();
    renderHypeColourControls();
    scheduleHypeRender(0);
  } else {
    state.colorOverrides[state.selectedColor] = normalized;
    if (state.processed?.colours[state.selectedColor]?.isFloatingSupport) {
      state.floatingSupportColour = normalized;
    }
    state.frontColoursCustomized = true;
  }
  updatePopoverInputs(normalized);
  if (state.selectedColourTarget.type !== 'hype' && state.selectedColourTarget.type !== 'hypePendant') schedulePreviewRender();
  if (state.wizardStep === 'details') renderDetailsStep();
  if (state.wizardStep === 'mapping') renderMappingStep();
  if (state.wizardStep === 'vector') renderVectorStep();
}

function applyRgbInputs() {
  const rgb = [els.rgbR, els.rgbG, els.rgbB].map((input) => clamp(Number(input.value) || 0, 0, 255));
  applySelectedColour(rgbToHex(rgb));
}

function initThreeStage() {
  if (!window.THREE) return;
  const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true, preserveDrawingBuffer: true });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
  renderer.shadowMap.enabled = true;
  renderer.shadowMap.type = THREE.PCFSoftShadowMap;
  renderer.outputEncoding = THREE.sRGBEncoding;
  if (THREE.ACESFilmicToneMapping) renderer.toneMapping = THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.05;
  renderer.domElement.className = 'three-canvas';
  els.stage.appendChild(renderer.domElement);

  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(34, 1, 1, 1200);
  camera.position.set(0, 10, 430);
  camera.lookAt(0, 0, 0);

  const hemi = new THREE.HemisphereLight(0xe7edf0, 0x111312, 0.82);
  scene.add(hemi);

  const key = new THREE.DirectionalLight(0xfff7e8, 0.78);
  key.position.set(-190, 260, 330);
  key.castShadow = true;
  key.shadow.mapSize.set(1024, 1024);
  scene.add(key);

  const rim = new THREE.DirectionalLight(0x92a2aa, 0.62);
  rim.position.set(220, 110, -250);
  scene.add(rim);

  const floorFill = new THREE.DirectionalLight(0xffecc4, 0.34);
  floorFill.position.set(0, -140, 260);
  scene.add(floorFill);

  const floor = new THREE.Mesh(
    new THREE.PlaneBufferGeometry(760, 440),
    new THREE.ShadowMaterial({ color: 0x000000, opacity: 0.24 }),
  );
  floor.rotation.x = -Math.PI / 2;
  floor.position.set(0, -105, -40);
  floor.receiveShadow = true;
  scene.add(floor);

  state.three = { renderer, scene, camera, floor, group: null, floorGroup: null, resources: [], resizeObserver: null };
  resizeThree();
  window.addEventListener('resize', resizeThree);
  if (window.ResizeObserver) {
    state.three.resizeObserver = new ResizeObserver(() => resizeThree());
    state.three.resizeObserver.observe(els.stage);
  }
  renderThree();
}

function resizeThree() {
  if (!state.three) return;
  const rect = els.stage.getBoundingClientRect();
  state.three.renderer.setSize(Math.max(1, rect.width), Math.max(1, rect.height), false);
  state.three.camera.aspect = Math.max(1, rect.width) / Math.max(1, rect.height);
  applyPreviewZoom();
  updateThreeModelPosition();
  state.three.camera.updateProjectionMatrix();
  renderThree();
}

function renderThree() {
  if (!state.three) return;
  state.three.renderer.render(state.three.scene, state.three.camera);
}

function applyIllumination() {
  els.stage.classList.toggle('lights-on', state.illuminated);
  els.stage.classList.toggle('lights-off', !state.illuminated);
  if (els.lightToggleLabel) els.lightToggleLabel.textContent = state.illuminated ? 'lights on' : 'lights off';
  const lighting = state.three?.group?.userData?.lighting;
  if (lighting) {
    lighting.illuminatedFaceMaterial.opacity = state.illuminated ? 0.006 : 0;
    lighting.diffusionMaterial.opacity = state.illuminated ? 0.058 : 0.014;
    lighting.glowMaterial.opacity = state.illuminated ? 0.034 : 0.004;
    lighting.innerLight.intensity = state.illuminated ? 0.035 : 0.004;
    lighting.groundGlowMaterial.opacity = state.illuminated ? 0.38 : 0.018;
    lighting.groundHaloMaterial.opacity = state.illuminated ? 0.16 : 0;
    lighting.keyholeInteriorMaterial.opacity = state.illuminated ? 1 : 0.54;
    lighting.keyholeInteriorMaterial.color.copy(makeThreeColour(state.illuminated ? '#ffffff' : '#343838'));
    updateFloorEffects();
    renderThree();
  }
}

function getPreviewZoomLimits() {
  return isMobilePreviewViewport()
    ? { min: MOBILE_PREVIEW_ZOOM_MIN, max: MOBILE_PREVIEW_ZOOM_MAX }
    : { min: DESKTOP_PREVIEW_ZOOM_MIN, max: DESKTOP_PREVIEW_ZOOM_MAX };
}

function setPreviewZoom(value, options = {}) {
  const limits = getPreviewZoomLimits();
  state.previewZoom = clamp(Number(value) || 1, limits.min, limits.max);
  state.previewPan = clampPreviewPan(state.previewPan);
  applyPreviewZoom();
  if (options.render === false) return;
  renderActivePreviewFrame();
}

function applyPreviewZoom() {
  const limits = getPreviewZoomLimits();
  const zoom = clamp(Number(state.previewZoom) || 1, limits.min, limits.max);
  state.previewZoom = zoom;
  if (els.previewZoomReset) els.previewZoomReset.textContent = isMobilePreviewViewport() ? 'Reset View' : `${Math.round(zoom * 100)}%`;
  if (state.three?.camera) {
    state.three.camera.position.z = 430 / zoom;
    state.three.camera.lookAt(0, 0, 0);
    state.three.camera.updateProjectionMatrix();
    updateThreeModelPosition();
  }
  if (state.hypeThree?.camera) {
    state.hypeThree.camera.near = HYPE_CAMERA_NEAR;
    state.hypeThree.camera.far = HYPE_CAMERA_FAR;
    frameHypeCamera({ smooth: state.productType === 'hype' });
    state.hypeThree.camera.updateProjectionMatrix();
  }
  if (els.modelStack) {
    els.modelStack.style.scale = zoom.toFixed(3);
  }
  if (els.hypeChainRender) {
    els.hypeChainRender.style.setProperty('--hype-zoom', zoom.toFixed(3));
    els.hypeChainRender.style.setProperty('--preview-pan-x', `${getPreviewPan().x.toFixed(1)}px`);
    els.hypeChainRender.style.setProperty('--preview-pan-y', `${getPreviewPan().y.toFixed(1)}px`);
  }
}

function getPreviewPan() {
  return {
    x: Number(state.previewPan?.x) || 0,
    y: Number(state.previewPan?.y) || 0,
  };
}

function clampPreviewPan(pan = {}) {
  const rect = els.stage?.getBoundingClientRect?.();
  const zoom = Number(state.previewZoom) || 1;
  const maxX = Math.max(48, (rect?.width || 360) * 0.38 * zoom);
  const maxY = Math.max(48, (rect?.height || 360) * 0.34 * zoom);
  return {
    x: clamp(Number(pan.x) || 0, -maxX, maxX),
    y: clamp(Number(pan.y) || 0, -maxY, maxY),
  };
}

function setPreviewPan(x, y, options = {}) {
  state.previewPan = clampPreviewPan({ x, y });
  applyPreviewPan();
  if (options.render === false) return;
  renderActivePreviewFrame();
}

function applyPreviewPan() {
  state.previewPan = clampPreviewPan(state.previewPan);
  applyRotation();
  if (state.three?.group) updateThreeModelPosition();
  if (state.hypeThree?.group) applyHypeGroupRotation();
  if (els.hypeChainRender) {
    const pan = getPreviewPan();
    els.hypeChainRender.style.setProperty('--preview-pan-x', `${pan.x.toFixed(1)}px`);
    els.hypeChainRender.style.setProperty('--preview-pan-y', `${pan.y.toFixed(1)}px`);
  }
}

function resetPreviewView() {
  state.previewZoom = 1;
  state.previewPan = { x: 0, y: 0 };
  applyPreviewZoom();
  applyPreviewPan();
  renderActivePreviewFrame();
}

function renderActivePreviewFrame() {
  if (state.productType === 'hype') renderHypeThree();
  else renderThree();
}

function clearThreeModel() {
  if (!state.three?.group && !state.three?.floorGroup) return;
  if (state.three.group) state.three.scene.remove(state.three.group);
  if (state.three.floorGroup) state.three.scene.remove(state.three.floorGroup);
  state.three.resources.forEach((resource) => {
    if (resource?.dispose) resource.dispose();
  });
  state.three.group = null;
  state.three.floorGroup = null;
  state.three.resources = [];
  renderThree();
}

function updateThreeModelPosition() {
  if (!state.three?.group) return;
  const bounds = state.three.group.userData?.bounds;
  const pan = getPreviewPan();
  state.three.group.position.x = pan.x * 0.36;
  state.three.group.position.y = getThreeModelYOffset(bounds) - pan.y * 0.36;
  if (state.three.floorGroup && bounds) {
    state.three.floorGroup.userData.floorY = state.three.group.position.y + bounds.minY;
    updateFloorEffects();
  }
}

function getThreeModelYOffset(bounds = null) {
  if (!bounds) return isResponsiveViewport() ? -26 : 10;
  const floorY = isResponsiveViewport() ? -94 : -74;
  return floorY - bounds.minY;
}

function isResponsiveViewport() {
  return window.matchMedia('(max-width: 880px)').matches;
}

function isMobilePreviewViewport() {
  return window.matchMedia('(max-width: 768px)').matches;
}

function buildThreeModel() {
  if (!state.three || !state.processed || !window.THREE) return;
  clearThreeModel();
  const processed = state.processed;
  const shellDepth = SIZE_PRESETS[state.size].depth;
  const bounds = getModelBounds(processed);
  const facePoints = silhouetteToThreePoints(processed.silhouette, bounds, 1);
  const frontBackerPoints = offsetThreePolygon(facePoints, 0.45);
  const bezelInnerPoints = offsetThreePolygon(facePoints, 0.15);
  const shellOuterPoints = offsetThreePolygon(facePoints, 1.05);
  const backPoints = offsetThreePolygon(facePoints, 1.05);
  const faceShape = makeThreeShape(facePoints);
  const frontBackerShape = makeThreeShape(frontBackerPoints);
  const sideColour = normalizeHex(state.shellColours.side);
  const backColour = normalizeHex(state.shellColours.back);
  const sideMaterialColour = liftDarkFrameColour(sideColour);
  const backMaterialColour = liftDarkFrameColour(backColour);
  const resources = state.three.resources;
  const artworkCanvas = createThreeArtworkCanvas(processed);
  const texture = new THREE.CanvasTexture(artworkCanvas);
  texture.anisotropy = 8;
  texture.encoding = THREE.sRGBEncoding;
  texture.minFilter = THREE.LinearFilter;
  texture.magFilter = THREE.LinearFilter;
  texture.generateMipmaps = false;
  texture.wrapS = THREE.ClampToEdgeWrapping;
  texture.wrapT = THREE.ClampToEdgeWrapping;
  texture.needsUpdate = true;
  resources.push(texture);

  const group = new THREE.Group();
  group.position.y = getThreeModelYOffset(bounds);
  group.userData.bounds = bounds;

  const sideMaterial = new THREE.MeshStandardMaterial({
    color: makeThreeColour(sideMaterialColour),
    roughness: 0.52,
    metalness: 0.18,
    emissive: makeThreeColour('#0b0e0e'),
    emissiveIntensity: 0.12,
  });
  const backMaterial = new THREE.MeshStandardMaterial({
    color: makeThreeColour(backMaterialColour),
    roughness: 0.56,
    metalness: 0.16,
    emissive: makeThreeColour('#080a0a'),
    emissiveIntensity: 0.08,
  });
  const frontBackerMaterial = new THREE.MeshStandardMaterial({
    color: makeThreeColour(sideMaterialColour),
    roughness: 0.48,
    metalness: 0.2,
    emissive: makeThreeColour('#0b0e0e'),
    emissiveIntensity: 0.11,
  });
  const keyholeInteriorMaterial = new THREE.MeshBasicMaterial({
    map: texture,
    color: makeThreeColour(state.illuminated ? '#ffffff' : '#343838'),
    side: THREE.BackSide,
    transparent: true,
    opacity: state.illuminated ? 1 : 0.54,
    alphaTest: 0.03,
    depthWrite: true,
    depthTest: true,
    toneMapped: false,
  });
  resources.push(sideMaterial, backMaterial, frontBackerMaterial, keyholeInteriorMaterial);

  const shellBounds = getThreePointBounds(backPoints);
  const keyholeAnchor = getBackPlateKeyholeAnchor(processed, bounds) || { x: shellBounds.centerX, y: shellBounds.centerY };
  const keyholeBounds = {
    ...bounds,
    keyholeX: keyholeAnchor.x,
    keyholeY: keyholeAnchor.y,
  };

  const floorGroup = new THREE.Group();
  floorGroup.userData = {
    bounds,
    floorY: group.position.y + bounds.minY,
  };

  const groundGlowTexture = makeGroundGlowTexture();
  const groundGlowMaterial = new THREE.MeshBasicMaterial({
    map: groundGlowTexture,
    transparent: true,
    opacity: state.illuminated ? 0.44 : 0.02,
    depthWrite: false,
    toneMapped: false,
  });
  const groundGlowGeometry = new THREE.PlaneBufferGeometry(bounds.width * 1.42, Math.max(26, bounds.height * 0.28));
  const groundGlow = new THREE.Mesh(groundGlowGeometry, groundGlowMaterial);
  groundGlow.name = 'floorGlow';
  groundGlow.renderOrder = 0;
  floorGroup.add(groundGlow);
  resources.push(groundGlowTexture, groundGlowMaterial, groundGlowGeometry);

  const groundHaloTexture = makeGroundHaloTexture();
  const groundHaloMaterial = new THREE.MeshBasicMaterial({
    map: groundHaloTexture,
    transparent: true,
    opacity: state.illuminated ? 0.2 : 0,
    depthWrite: false,
    toneMapped: false,
  });
  const groundHaloGeometry = new THREE.PlaneBufferGeometry(bounds.width * 1.72, Math.max(34, bounds.height * 0.34));
  const groundHalo = new THREE.Mesh(groundHaloGeometry, groundHaloMaterial);
  groundHalo.name = 'floorHalo';
  groundHalo.renderOrder = 0;
  floorGroup.add(groundHalo);
  resources.push(groundHaloTexture, groundHaloMaterial, groundHaloGeometry);

  const contactShadowTexture = makeProjectedShadowTexture(processed, 0.22, 1.2);
  const contactShadowMaterial = new THREE.MeshBasicMaterial({
    map: contactShadowTexture,
    transparent: true,
    opacity: 0.48,
    depthWrite: false,
    toneMapped: false,
  });
  const contactShadowGeometry = new THREE.PlaneBufferGeometry(bounds.width * 1.08, Math.max(18, bounds.height * 0.16));
  const contactShadow = new THREE.Mesh(contactShadowGeometry, contactShadowMaterial);
  contactShadow.name = 'contactShadow';
  contactShadow.renderOrder = 0;
  floorGroup.add(contactShadow);
  resources.push(contactShadowTexture, contactShadowMaterial, contactShadowGeometry);

  const castShadowTexture = makeProjectedShadowTexture(processed, 0.28, 1.0);
  const castShadowMaterial = new THREE.MeshBasicMaterial({
    map: castShadowTexture,
    transparent: true,
    opacity: 0.34,
    depthWrite: false,
    toneMapped: false,
  });
  const castShadowGeometry = new THREE.PlaneBufferGeometry(bounds.width * 1.75, Math.max(26, bounds.height * 0.28));
  const castShadow = new THREE.Mesh(castShadowGeometry, castShadowMaterial);
  castShadow.name = 'castShadow';
  castShadow.renderOrder = 0;
  floorGroup.add(castShadow);
  resources.push(castShadowTexture, castShadowMaterial, castShadowGeometry);

  const wallOcclusionTexture = makeWallOcclusionTexture(processed);
  const wallOcclusionMaterial = new THREE.MeshBasicMaterial({
    map: wallOcclusionTexture,
    transparent: true,
    opacity: 0.34,
    depthWrite: false,
    depthTest: true,
    toneMapped: false,
  });
  const wallOcclusionGeometry = new THREE.PlaneBufferGeometry(bounds.width * 1.42, bounds.height * 1.42);
  const wallOcclusion = new THREE.Mesh(wallOcclusionGeometry, wallOcclusionMaterial);
  wallOcclusion.name = 'wallOcclusion';
  wallOcclusion.renderOrder = -2;
  floorGroup.add(wallOcclusion);
  resources.push(wallOcclusionTexture, wallOcclusionMaterial, wallOcclusionGeometry);

  const wallHaloTexture = makeWallHaloTexture(processed);
  const wallHaloMaterial = new THREE.MeshBasicMaterial({
    map: wallHaloTexture,
    transparent: true,
    opacity: state.illuminated ? 0.16 : 0.01,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
    depthTest: true,
    toneMapped: false,
  });
  const wallHaloGeometry = new THREE.PlaneBufferGeometry(bounds.width * 1.5, bounds.height * 1.5);
  const wallHalo = new THREE.Mesh(wallHaloGeometry, wallHaloMaterial);
  wallHalo.name = 'wallHalo';
  wallHalo.renderOrder = -1;
  floorGroup.add(wallHalo);
  resources.push(wallHaloTexture, wallHaloMaterial, wallHaloGeometry);

  state.three.floorGroup = floorGroup;
  state.three.scene.add(floorGroup);
  updateFloorEffects();

  const shellGeometry = new THREE.ExtrudeBufferGeometry(makeBackPlateShape(shellOuterPoints, keyholeBounds), {
    depth: shellDepth,
    bevelEnabled: true,
    bevelSize: 0.22,
    bevelThickness: 0.22,
    bevelSegments: 2,
    curveSegments: 2,
  });
  shellGeometry.translate(0, 0, -shellDepth);
  shellGeometry.computeVertexNormals();
  const shell = new THREE.Mesh(shellGeometry, [sideMaterial, sideMaterial]);
  shell.castShadow = true;
  shell.receiveShadow = true;
  group.add(shell);
  resources.push(shellGeometry);

  const backLipGeometry = new THREE.ExtrudeBufferGeometry(makeBackPlateShape(backPoints, keyholeBounds), {
    depth: 2.8,
    bevelEnabled: true,
    bevelSize: 0.26,
    bevelThickness: 0.26,
    bevelSegments: 2,
  });
  backLipGeometry.translate(0, 0, -shellDepth - 2.8);
  const backPlate = new THREE.Mesh(backLipGeometry, backMaterial);
  backPlate.castShadow = true;
  backPlate.receiveShadow = true;
  group.add(backPlate);
  resources.push(backLipGeometry);

  const keyholeInteriorGeometry = new THREE.PlaneBufferGeometry(bounds.width, bounds.height);
  const keyholeInterior = new THREE.Mesh(keyholeInteriorGeometry, keyholeInteriorMaterial);
  keyholeInterior.position.z = 2.72;
  keyholeInterior.name = 'keyholeInteriorLogoPlane';
  group.add(keyholeInterior);
  resources.push(keyholeInteriorGeometry);

  const frontBackerGeometry = new THREE.ShapeBufferGeometry(frontBackerShape);
  const frontBacker = new THREE.Mesh(frontBackerGeometry, frontBackerMaterial);
  frontBacker.position.z = 1.45;
  frontBacker.renderOrder = 1;
  frontBacker.castShadow = true;
  frontBacker.receiveShadow = true;
  group.add(frontBacker);
  resources.push(frontBackerGeometry);

  const bezelGeometry = new THREE.ExtrudeBufferGeometry(makeThreeRingShape(shellOuterPoints, bezelInnerPoints), {
    depth: 3.2,
    bevelEnabled: true,
    bevelSize: 0.32,
    bevelThickness: 0.32,
    bevelSegments: 2,
    curveSegments: 2,
  });
  bezelGeometry.translate(0, 0, -0.35);
  bezelGeometry.computeVertexNormals();
  const bezel = new THREE.Mesh(bezelGeometry, sideMaterial);
  bezel.castShadow = true;
  bezel.receiveShadow = true;
  bezel.renderOrder = 2;
  group.add(bezel);
  resources.push(bezelGeometry);

  const faceGeometry = new THREE.PlaneBufferGeometry(bounds.width, bounds.height);
  const faceMaterial = new THREE.MeshStandardMaterial({
    map: texture,
    color: makeThreeColour(state.illuminated ? '#ffffff' : '#cfd4d1'),
    emissive: makeThreeColour('#fff2c8'),
    emissiveMap: texture,
    emissiveIntensity: state.illuminated ? 0.004 : 0.0015,
    roughness: 0.86,
    metalness: 0.004,
    transparent: true,
    alphaTest: 0.03,
    side: THREE.FrontSide,
    depthWrite: true,
  });
  const face = new THREE.Mesh(faceGeometry, faceMaterial);
  face.position.z = 3.15;
  face.renderOrder = 4;
  face.castShadow = true;
  face.receiveShadow = true;
  group.add(face);
  resources.push(faceGeometry, faceMaterial);

  const illuminatedFaceGeometry = faceGeometry.clone();
  const illuminatedFaceMaterial = new THREE.MeshBasicMaterial({
    map: texture,
    color: 0xfff0bf,
    transparent: true,
    opacity: state.illuminated ? 0.006 : 0,
    alphaTest: 0.03,
    side: THREE.FrontSide,
    depthWrite: false,
    toneMapped: false,
    blending: THREE.AdditiveBlending,
  });
  const illuminatedFace = new THREE.Mesh(illuminatedFaceGeometry, illuminatedFaceMaterial);
  illuminatedFace.position.z = 3.22;
  illuminatedFace.renderOrder = 5;
  group.add(illuminatedFace);
  resources.push(illuminatedFaceGeometry, illuminatedFaceMaterial);

  const diffusionTexture = makeLedDiffusionTexture(bounds);
  resources.push(diffusionTexture);
  const diffusionGeometry = faceGeometry.clone();
  const diffusionMaterial = new THREE.MeshBasicMaterial({
    map: diffusionTexture,
    transparent: true,
    opacity: state.illuminated ? 0.058 : 0.014,
    side: THREE.FrontSide,
    depthWrite: false,
    toneMapped: false,
  });
  const diffusion = new THREE.Mesh(diffusionGeometry, diffusionMaterial);
  diffusion.position.z = 3.26;
  diffusion.renderOrder = 6;
  group.add(diffusion);
  resources.push(diffusionGeometry, diffusionMaterial);

  const glowGeometry = new THREE.ShapeBufferGeometry(faceShape);
  const glowMaterial = new THREE.MeshBasicMaterial({
    color: 0xffe8b0,
    transparent: true,
    opacity: state.illuminated ? 0.06 : 0.004,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
  });
  const glow = new THREE.Mesh(glowGeometry, glowMaterial);
  glow.position.z = 3.08;
  glow.scale.set(1.02, 1.02, 1);
  glow.renderOrder = 3;
  group.add(glow);
  resources.push(glowGeometry, glowMaterial);

  const innerLight = new THREE.PointLight(0xffedbd, state.illuminated ? 0.035 : 0.004, 140);
  innerLight.position.set(0, 0, -8);
  group.add(innerLight);
  group.userData.lighting = {
    faceMaterial,
    sideMaterial,
    backMaterial,
    frontBackerMaterial,
    illuminatedFaceMaterial,
    diffusionMaterial,
    glowMaterial,
    innerLight,
    groundGlowMaterial,
    groundHaloMaterial,
    wallOcclusionMaterial,
    wallHaloMaterial,
    keyholeInteriorMaterial,
  };

  state.three.group = group;
  state.three.scene.add(group);
  els.stage.classList.add('three-active');
  applyRotation();
  renderThree();
  requestAnimationFrame(() => els.stage.classList.add('preview-ready'));
}

function updateFloorEffects() {
  if (!state.three?.floorGroup || !window.THREE) return;
  const floorGroup = state.three.floorGroup;
  const bounds = floorGroup.userData?.bounds;
  const floorY = floorGroup.userData?.floorY;
  if (!bounds || typeof floorY !== 'number') return;
  const modelY = state.three.group?.position?.y ?? floorY - bounds.minY;

  const shellDepth = SIZE_PRESETS[state.size].depth;
  const yaw = THREE.Math.degToRad(state.rotation.y || 0);
  const pitch = THREE.Math.degToRad(state.rotation.x || 0);
  const yawSide = Math.sin(yaw);
  const sideAmount = Math.abs(yawSide);
  const topAmount = clamp(Math.abs(Math.sin(pitch)), 0, 1);
  const depthZ = -shellDepth - 24;
  const frontAmount = clamp((Math.cos(yaw) + 1) / 2, 0, 1);
  const lit = state.illuminated ? 1 : 0;
  const lighting = state.three.group?.userData?.lighting;

  if (lighting) {
    const diffuserStrength = lit ? 0.045 + frontAmount * 0.014 + sideAmount * 0.01 : 0.014;
    const edgeGlowStrength = lit ? 0.024 + frontAmount * 0.01 + sideAmount * 0.01 : 0.004;
    lighting.illuminatedFaceMaterial.opacity = lit ? 0.004 + frontAmount * 0.005 : 0;
    lighting.diffusionMaterial.opacity = diffuserStrength;
    lighting.glowMaterial.opacity = edgeGlowStrength;
    lighting.innerLight.intensity = lit ? 0.032 + sideAmount * 0.012 : 0.004;
    const faceBrightness = lit ? 0.965 + sideAmount * 0.01 : 0.74;
    lighting.faceMaterial.color.setRGB(faceBrightness, faceBrightness, faceBrightness);
    lighting.faceMaterial.emissiveIntensity = lit ? 0.003 + sideAmount * 0.004 : 0.0015;
    lighting.faceMaterial.roughness = lit ? 0.84 + sideAmount * 0.06 : 0.88;
    lighting.sideMaterial.emissiveIntensity = lit ? 0.08 + sideAmount * 0.035 : 0.018;
    lighting.frontBackerMaterial.emissiveIntensity = lit ? 0.075 + sideAmount * 0.03 : 0.014;
    lighting.backMaterial.emissiveIntensity = lit ? 0.04 : 0.008;
    lighting.wallOcclusionMaterial.opacity = 0.2 + sideAmount * 0.16 + topAmount * 0.04 - lit * frontAmount * 0.035;
    lighting.wallHaloMaterial.opacity = lit ? 0.08 + frontAmount * 0.06 + sideAmount * 0.025 : 0.004;
    lighting.keyholeInteriorMaterial.opacity = lit ? 1 : 0.54;
    lighting.keyholeInteriorMaterial.color.copy(makeThreeColour(lit ? '#ffffff' : '#343838'));
  }

  if (state.three.floor) {
    state.three.floor.position.y = floorY - 1;
    state.three.floor.position.z = depthZ - 10;
  }

  const floorGlow = floorGroup.getObjectByName('floorGlow');
  if (floorGlow) {
    floorGlow.position.set(
      yawSide * bounds.width * 0.12,
      floorY - bounds.height * (0.28 + topAmount * 0.04),
      depthZ + 4,
    );
    floorGlow.rotation.z = yawSide * 0.06;
    floorGlow.scale.set(0.95 + sideAmount * 0.32, 0.86 + topAmount * 0.12, 1);
    floorGlow.material.opacity = lit ? 0.28 + frontAmount * 0.08 : 0.01;
  }

  const floorHalo = floorGroup.getObjectByName('floorHalo');
  if (floorHalo) {
    floorHalo.position.set(
      yawSide * bounds.width * 0.06,
      floorY - bounds.height * (0.2 + topAmount * 0.03),
      depthZ + 3,
    );
    floorHalo.rotation.z = yawSide * 0.035;
    floorHalo.scale.set(0.96 + sideAmount * 0.22, 0.72 + topAmount * 0.12, 1);
    floorHalo.material.opacity = lit ? 0.1 + frontAmount * 0.04 : 0;
  }

  const contactShadow = floorGroup.getObjectByName('contactShadow');
  if (contactShadow) {
    contactShadow.position.set(
      yawSide * bounds.width * 0.06,
      floorY - bounds.height * 0.015,
      depthZ + 2,
    );
    contactShadow.rotation.z = yawSide * 0.035;
    contactShadow.scale.set(0.9 + sideAmount * 0.42, 0.54 + topAmount * 0.18, 1);
    contactShadow.material.opacity = 0.36 + sideAmount * 0.1;
  }

  const castShadow = floorGroup.getObjectByName('castShadow');
  if (castShadow) {
    castShadow.position.set(
      -yawSide * bounds.width * (0.42 + sideAmount * 0.58),
      floorY - bounds.height * (0.055 + topAmount * 0.04),
      depthZ + 1,
    );
    castShadow.rotation.z = -yawSide * 0.08;
    castShadow.scale.set(0.9 + sideAmount * 0.78, 0.5 + topAmount * 0.32, 1);
    castShadow.material.opacity = 0.14 + sideAmount * 0.2 + topAmount * 0.06;
  }

  const wallZ = -shellDepth - 10;
  const shadowShiftX = -yawSide * bounds.width * (0.08 + sideAmount * 0.18);
  const shadowShiftY = -bounds.height * (0.035 + topAmount * 0.03);
  const wallOcclusion = floorGroup.getObjectByName('wallOcclusion');
  if (wallOcclusion) {
    wallOcclusion.position.set(shadowShiftX, modelY + shadowShiftY, wallZ);
    wallOcclusion.rotation.z = -yawSide * 0.035;
    wallOcclusion.scale.set(1.02 + sideAmount * 0.22, 1.02 + topAmount * 0.12, 1);
    wallOcclusion.material.opacity = clamp(0.22 + sideAmount * 0.18 + topAmount * 0.04 - lit * frontAmount * 0.045, 0.13, 0.46);
  }

  const wallHalo = floorGroup.getObjectByName('wallHalo');
  if (wallHalo) {
    wallHalo.position.set(
      shadowShiftX * 0.44,
      modelY - bounds.height * (0.015 + topAmount * 0.012),
      wallZ + 0.18,
    );
    wallHalo.rotation.z = -yawSide * 0.02;
    wallHalo.scale.set(1.04 + sideAmount * 0.16, 1.04 + topAmount * 0.08, 1);
    wallHalo.material.opacity = lit ? 0.08 + frontAmount * 0.06 + sideAmount * 0.025 : 0.004;
  }
}

function makeLedDiffusionTexture() {
  const canvas = document.createElement('canvas');
  canvas.width = 512;
  canvas.height = 512;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  const softSpots = [
    [0.22, 0.22, 0.18, 0.09],
    [0.76, 0.28, 0.16, 0.07],
    [0.42, 0.55, 0.22, 0.08],
    [0.66, 0.72, 0.2, 0.07],
    [0.28, 0.78, 0.14, 0.06],
  ];
  softSpots.forEach(([x, y, radius, alpha]) => {
    const gradient = ctx.createRadialGradient(
      x * canvas.width,
      y * canvas.height,
      0,
      x * canvas.width,
      y * canvas.height,
      radius * canvas.width,
    );
    gradient.addColorStop(0, `rgba(0,0,0,${alpha})`);
    gradient.addColorStop(1, 'rgba(0,0,0,0)');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  });
  const texture = new THREE.CanvasTexture(canvas);
  texture.needsUpdate = true;
  texture.minFilter = THREE.LinearFilter;
  texture.magFilter = THREE.LinearFilter;
  texture.generateMipmaps = false;
  return texture;
}

